@ARTICLE{10.1038/s41598-026-44125-z,
	author = {Zou Q and Zhang L and Li M and Wang B and Cao Y and Zhang X and Qu J},
	title = {Correlation between anti-retinal antibodies and lupus retinopathy in systemic lupus erythematosus.},
	journal = {Sci Rep},
	year = {2026},
	abstract = {Lupus retinopathy (LR) is one of the most frequent and serious ocular complications of systemic lupus erythematosus (SLE), because it may cause irreversible visual impairment. The aim of this study was to evaluate the association between serum anti-retinal antibodies levels of SLE patients and the incidence of LR. Levels of serum anti-α-enolase antibody (Ab), anti-arrestin Ab, anti-recoverin Ab and anti-IRBP3 Ab were detected in 89 SLE patients (divided into LR group and non-LR group) and 81 healthy controls by enzyme-linked immunosorbent assay (ELISA). The correlation between these four anti-retinal Ab, SLE activity and the incidence of LR was evaluated. LR group had a higher SLE disease activity index (average SLEDAI score, 18 (7) versus 9 (5), P < 0.001), higher frequency of pleurisy (40% versus 20.4%, P = 0.044) and lower level of hemoglobin (102.343 ± 23.157 versus 112.759 ± 19.678, P = 0.025) comparing to non-LR group. LR group had higher levels of anti-α-enolase than non-LR group (P = 0.033) and control group (P < 0.0001). The levels of anti-recoverin in LR group was higher than non-LR group (P = 0.036) and control group (P < 0.0001), while the difference was not significant between non-LR group and control group (P = 0.109). Using combination of anti-α-enolase Ab and anti-recoverin Ab to diagnose LR in SLE patients is more effective (with area under the receiver operating characteristic curve (AUC): 72.68%) than use anti-α-enolase Ab (AUC: 65.65%) or anti-recoverin (AUC: 61.96%) only. Our results suggested that anti-α-enolase and anti-recoverin may be used as potential biomarkers of lupus retinopathy in SLE patients.},
	doi = {10.1038/s41598-026-44125-z},
	pmid = {41826673}
}

@ARTICLE{10.1016/j.ejca.2026.116594,
	author = {Cuzzubbo S and Vogrig A and Louis E and Philippakis E and Ursu R and Ezine E, Lebbé C and Aprile G and Couturier A and Carpentier AF},
	title = {Optic neuropathies induced by immune checkpoint inhibitors: A case series and systematic review of the literature.},
	journal = {Eur J Cancer},
	year = {2026},
	abstract = {INTRODUCTION: Immune checkpoint inhibitor (ICI)-related optic neuritis is rare but clinically significant as visual sequelae are reported in around half of affected patients. MATERIALS AND METHODS: We retrospectively collected all cases of ICI-related optic neuropathy referred to two tertiary centers. A systematic review of PubMed, Embase, and Medline was conducted following PRISMA guidelines. Cases were classified into: i) optic neuritis, defined by the presence of consistent symptoms (visual loss, dyschromatopsia, afferent pupillary defect) and optic nerve abnormalities on MRI or visual evoked potentials (VEPs); ii) papillitis, defined by any visual disturbance associated with optic disc oedema and absence of optic neuropathy signs on MRI imaging or VEPs. RESULTS: Fifty cases were identified. The most common presentation was bilateral, painless visual acuity reduction with papilledema. All optic neuritis cases involved vision loss compared to 60 % of papillitis patients, who also reported scotomas, photopsia, or floaters. Papillitis was frequently associated with uveitis, either isolated or as part of Vogt-Koyanagi-Harada-like syndrome, whereas optic neuritis was more often associated with immune-related neurological toxicities, including neuromyelitis optica spectrum disorder. Despite immunomodulatory treatment, visual deficits persisted in 60 % of cases - rising to nearly 80 % in optic neuritis cases. Seven patients with papillitis and one with optic neuropathy resumed ICIs without recurrence. CONCLUSIONS: Two distinct patterns of ICI-induced optic neuropathy emerge: papillitis, usually associated with uveitis and Vogt-Koyanagi-Harada syndrome, and optic neuritis, linked to broader immune-related neurological toxicities and poorer outcomes. Our findings suggest that ICIs may be safely reintroduced after full recovery from ICI-related papillitis.},
	doi = {10.1016/j.ejca.2026.116594},
	pmid = {41759413 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/diagnostics16040627,
	author = {Ehrenberg S and Elizur Y and Ben-Shabat N and David P and Sharif K and Bernstein YS and Abu Hilwe I and Cohen AD and Watad A and Amital H and Patt YS},
	title = {Increased Risk of Incident Uveitis Among Patients with Psoriasis: A Nationwide Population-Based Cohort Study.},
	journal = {Diagnostics (Basel)},
	year = {2026},
	abstract = {Background: Psoriasis is a chronic systemic inflammatory disease with established extra-cutaneous manifestations. While the association between uveitis and spondyloarthritis (SpA)-related disorders is well recognized, the incident risk of uveitis among broader psoriasis populations remains inadequately defined due to methodological limitations and inconsistent findings across previous studies. We aimed to estimate the incidence of uveitis in a large, nationwide population-based cohort and identify specific clinical and treatment-related predictors of ocular inflammation. Methods: This retrospective cohort study utilised electronic health records from Clalit Health Services, Israel's largest health maintenance organization (2002-2024). We identified 157,360 patients with dermatologist-confirmed psoriasis and 156,927 age- and sex-matched controls. The primary outcome was incident uveitis, with risk estimated using Cox proportional hazards models. Within the psoriasis cohort, multivariable logistic regression was employed to identify predictors of uveitis, ensuring appropriate temporal sequencing between psoriasis treatment exposure and outcome. Results: Over a median follow-up of 12.6 years, psoriasis was associated with a significantly higher risk of incident uveitis (adjusted Hazard Ratio [aHR] 1.80; 95% CI, 1.50-2.15). Stratified analysis revealed a graded risk pattern: mild psoriasis showed no increased risk (aHR 1.01; 95% CI, 0.91-1.13), whereas severe disease (aHR 1.59; 95% CI, 1.25-2.03) and concomitant SpA (aHR 2.21; 95% CI, 1.87-2.61) demonstrated markedly elevated risks. Within the psoriasis cohort, independent predictors included SpA, diabetes mellitus, systemic lupus erythematosus, and sarcoidosis. Exposure to biologics, particularly etanercept (OR 3.37; 95% CI, 2.42-4.54), was associated with higher odds of uveitis, potentially reflecting higher disease severity. Conclusions: Incident uveitis risk in psoriasis is primarily driven by the magnitude of systemic inflammatory burden, with the highest risk observed in severe disease and those with concomitant SpA. Clinicians should maintain heightened vigilance for ocular symptoms in these high-risk subgroups to ensure timely intervention.},
	doi = {10.3390/diagnostics16040627},
	pmid = {41750775},
	note = {PMC12939956}
}

@ARTICLE{10.3389/fmed.2026.1755451,
	author = {Li F and Wu D and Zhu X},
	title = {Case Report: Vogt-Koyanagi-Harada syndrome complicated by secondary glaucoma: diagnostic insights and mechanistic correlations in uveitic ocular hypertension.},
	journal = {Front Med (Lausanne)},
	year = {2026},
	abstract = {INTRODUCTION: This case highlights an uncommon presentation of Vogt-Koyanagi-Harada (VKH) syndrome, in which acute angle-closure glaucoma (AACG) served as the initial ocular manifestation. This atypical onset may lead to misdiagnosis as primary angle-closure glaucoma. This report adds to the existing literature by emphasizing the diagnostic value of ciliary body imaging and the mechanistic link between inflammatory ciliary body detachment and secondary angle closure. CASE PRESENTATION: A 27-year-old woman presented with acute ocular pain, vision loss, and markedly elevated intraocular pressure (IOP). Important clinical findings included conjunctival congestion, corneal edema, medium-depth anterior chambers, and the absence of keratic precipitates or aqueous flare. Ultrasound biomicroscopy revealed a ciliary body detachment, whereas optical coherence tomography revealed multiple serous retinal detachments. The patient was initially misdiagnosed with glaucoma before a revised diagnosis of VKH syndrome-associated secondary AACG was made. INTERVENTIONS AND OUTCOMES: The patient was treated with intravenous methylprednisolone pulse therapy combined with topical corticosteroids, mydriatic agents, and IOP-lowering agents. Visual acuity and IOP gradually improved, and subretinal fluid completely resolved during follow-up. CONCLUSION: VKH syndrome rarely presents with AACG as the initial manifestation. Awareness of this presentation and careful imaging evaluation are essential to avoid misdiagnosis. Early and aggressive anti-inflammatory therapy remains key to reversing both angle closure and retinal pathology. This case highlights the importance of considering autoimmune uveitis in patients with atypical angle-closure glaucoma.},
	doi = {10.3389/fmed.2026.1755451},
	pmid = {41743100},
	note = {PMC12930358}
}

@ARTICLE{10.3389/fimmu.2026.1724780,
	author = {Triggianese P and Capparelli E and D'Antonio A and Nesi C and Lombardo M and Kroegler B and Bergamini A and Mancino R and Mitterhofer AP and Della-Morte D and Nucci C and Cesareo M and Martucci A},
	title = {Reduced retinal microvascular density in patients with mixed connective tissue disease: an exploratory pilot study on the interplay between aging, renal function, and complement system.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {BACKGROUND: Mixed connective tissue disease (MCTD) is a systemic autoimmune disease with overlapping features with systemic lupus erythematosus, systemic sclerosis, and inflammatory idiopathic myopathies, characterized by anti-U1-RNP antibodies. Although subclinical retinal microvascular changes have been described in other connective tissue diseases, such data are lacking in patients with MCTD. METHODS: We performed a cross-sectional exploratory pilot study including patients with a defined diagnosis of MCTD according to one of the sets of classification criteria and age- and sex-matched healthy controls (HC), with elderly individuals equally distributed. Data on disease duration, renal function (creatinine and eGFR), and complement levels (C3 and C4) were recorded. All participants underwent optical coherence tomography angiography (OCT-A) to evaluate retinal vessel density (VD) using parafoveal, perifoveal, and foveal scans, whole images, and foveal avascular zones (FAZs). Nailfold videocapillaroscopy (NVC) was performed in patients with MCTD on four fingers of both hands to assess microangiopathy patterns. RESULTS: Patients with MCTD (n = 20, mean age 60.6 ± 11.4 years, 85% females) showed a significant reduction in both superficial and deep retinal VD across all evaluated regions compared with 20 HC. In patients with MCTD, deep retinal VD was inversely correlated with disease duration (r = -0.6, P = 0.0003) and directly correlated with eGFR (r = 0.4, P = 0.05). In patients with MCTD, C3 levels were positively correlated with age (r = 0.4, P = 0.03) and superficial parafoveal VD (r = 0.5, P = 0.008). In MCTD, NVC abnormalities, including non-specific microangiopathy and scleroderma patterns, occurred in 60% (n = 12) of cases and did not correlated with OCT-A findings. CONCLUSION: Patients with MCTD present subclinical retinal microvascular abnormalities detectable by OCT-A. Our hypothesis-generating study suggests that retinal vascular changes may be linked to disease duration, renal function, and complement levels. OCT-A may be a useful tool for assessing MCTD.},
	doi = {10.3389/fimmu.2026.1724780},
	pmid = {41727480 [Indexed for MEDLINE]},
	note = {PMC12916619}
}

@ARTICLE{10.3390/jcm15031309,
	author = {Aldarwesh A and Alwadman L and Almustanyir A and Alhassan M and Alluwimi MS and Alateeq A and Almaghlouth I},
	title = {Contrast Sensitivity and Colour Vision Tests for Early Detection and Monitoring of Hydroxychloroquine Retinal Toxicity: A Preliminary Study.},
	journal = {J Clin Med},
	year = {2026},
	abstract = {Background/Objectives: Hydroxychloroquine (HCQ) is used to manage various autoimmune diseases, including systemic lupus erythematosus. The prolonged use of HCQ is associated with retinopathy and irreversible visual loss due to retinal toxicity. Despite adherence to dosage regimens, patients may develop functional rather than structural changes, without detectable abnormalities on routine examination using visual acuity and optical coherence tomography (OCT). The study aimed to detect early signs of retinopathy in patients with autoimmune diseases treated with HCQ. Methods: This cross-sectional study included patients (n = 36) with autoimmune diseases who were treated with HCQ. The control group (n = 35) comprised healthy volunteers matched for age and sex. All participants were screened using colour vision tests (Ishihara, Konan ColourDX high definition [HD]), and retinal thickness was evaluated using OCT. Results: Our findings suggest a significant reduction in the contrast threshold of the L and M-cone photoreceptors compared with that of the control using Konan ColourDX HD. The OCT measurements revealed no statistically significant difference in retinal thickness between patients and controls; however, the contrast sensitivity test showed a significant reduction at all spatial frequencies (p < 0.0001). Conclusions: The current study suggests that the Konan ColourDX cone contrast test HD and contrast sensitivity testing may be valuable for periodic monitoring of patients receiving HCQ, potentially enabling earlier detection of toxicity. However, longitudinal studies with larger cohorts are needed to confirm these findings and to further establish the clinical value of these functional visual tests.},
	doi = {10.3390/jcm15031309},
	pmid = {41682990},
	note = {PMC12898785}
}

@ARTICLE{10.1016/j.preteyeres.2026.101445,
	author = {Xia L and Chen L and Dai L and Zhang P, Cifuentes-González C and Gupta V and Agrawal R and Yang P},
	title = {Vogt-Koyanagi-Harada disease under the lens: Insights from multimodal ocular imaging.},
	journal = {Prog Retin Eye Res},
	year = {2026},
	abstract = {Vogt-Koyanagi-Harada (VKH) disease is a multisystem autoimmune condition targeting melanocyte-rich ocular tissues, with inflammation primarily affecting the choroid. Despite advances in diagnostic criteria, disease staging and therapeutic decisions still rely heavily on clinical observation, with limited integration of imaging biomarkers. This review examines the evolving role of multimodal ocular imaging (MMI) in the diagnosis, monitoring, and prognostication of VKH. We critically appraise the utility and limitations of color fundus photography, fluorescein angiography (FFA), indocyanine green angiography (ICGA), optical coherence tomography (OCT), OCT angiography (OCTA), fundus autofluorescence, B-scan ultrasonography, ultrasound biomicroscopy and anterior segment photography. These modalities provide complementary insights into disease activity, from subclinical choroiditis and retinal pigment epithelium disruption to chronic sequelae such as subretinal fibrosis and choroidal atrophy. Key imaging features-such as choroidal thickening, hypofluorescent dark dots, RPE undulations, and flow voids-are described in the context of VKH pathophysiology and disease stage. We identify critical gaps in current practice, including the lack of standardized imaging-based definitions for relapse and remission, limited use of anterior segment imaging, and variability in access to advanced modalities. To address these challenges, we propose a stage-specific imaging framework to guide VKH assessment from prodromal to chronic phases. MMI has transitioned from a supportive to a central role in VKH management. Future efforts should prioritize the development of quantitative imaging biomarkers, standardization of grading systems, and integration of imaging into therapeutic algorithms to support timely, personalized care and prevent irreversible visual loss.},
	doi = {10.1016/j.preteyeres.2026.101445},
	pmid = {41644040 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ajo.2025.10.028,
	author = {Samalia PD and Sims JL and Tomkins-Netzer O and Lightman SL and Niederer RL},
	title = {Sex-Related Effects on the Clinical Presentation of Uveitis.},
	journal = {Am J Ophthalmol},
	year = {2026},
	abstract = {OBJECTIVE/PURPOSE: The primary aim of this study was to determine sex-related patterns of uveitic entities. Secondary aims included sex-related patterns of uveitic complications. DESIGN: Retrospective clinical cohort study. PARTICIPANTS: 5703 participants presenting with uveitis from January 2009 to December 2023 were included. MAIN OUTCOME MEASURES: uveitis entities and complications. RESULTS: 2870 (50.3%) participants were female and 2831 (49.6%) were male. Males presented at a significantly younger age than females (42.2 vs 45.0). Significant sex-based differences were observed in the prevalence of specific uveitic conditions. Females were more likely to develop multifocal choroiditis (female: male ratio 1.818:1), Vogt-Koyanagi-Harada syndrome (female: male ratio 2.136:1), birdshot chorioretinopathy (female: male ratio 2.800:1, punctate inner choroidopathy (female: male ratio 6.571:1), drug-induced uveitis (female: male ratio 2.833:1), Crohn's disease (female: male ratio 3.714:1) and multiple evanescent white dot syndrome (female: male ratio 5.000:1). In contrast, males were more likely to develop acute posterior multifocal placoid pigment epitheliopathy (female: male ratio 0.364:1), sympathetic ophthalmia (female: male ratio 0.353:1) and syphilis (female: male ratio 0.404:1). Cataract was significantly more common in females, and this remained significant after adjusting for age at presentation, anatomical location and bilaterality. Cystoid macular edema and epiretinal membrane were more frequent in females, whereas retinal detachment occurred more often in males. Bilateral vision loss occurred in 238 patients (4.2%) and was significantly more common in females (4.9% vs 3.5%). CONCLUSIONS: Sex appears to be a key factor influencing the underlying etiology and clinical course of uveitis. These findings underscore the importance of considering sex as a biological variable in the diagnosis, monitoring, and management of uveitis.},
	doi = {10.1016/j.ajo.2025.10.028},
	pmid = {41642701 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fmed.2026.1733153,
	author = {Huang Y and Wang Y and Ren Q},
	title = {Co-occurrence of Vogt-Koyanagi-Harada disease, diabetic retinopathy, and advanced chronic kidney disease: a case report.},
	journal = {Front Med (Lausanne)},
	year = {2026},
	abstract = {OBJECTIVE: This study aimed to report a case of Vogt-Koyanagi-Harada (VKH) disease in a 53-year-old man with renal failure and diabetes, highlighting the challenges in diagnosing VKH amidst complex systemic comorbidities. METHODS: A case report was conducted through a retrospective review of the patient's medical history, clinical presentations, diagnostic workup, and treatment course. RESULTS: A 53-year-old man with renal failure, hypoalbuminemia, and diabetes presented with blurred vision. Initial findings included bilateral serous retinal detachment with subretinal septa, choroidal thickening, and left eye vitreous hemorrhage, without anterior chamber inflammation. Subsequent anterior segment inflammation and a positive response to combined corticosteroids and adalimumab confirmed VKH. CONCLUSION: This case underscores the diagnostic complexity of VKH in patients with multiple systemic conditions. Corticosteroid management in such individuals requires meticulous attention, emphasizing the need for close monitoring of blood glucose and overall systemic status during treatment.},
	doi = {10.3389/fmed.2026.1733153},
	pmid = {41640516},
	note = {PMC12864085}
}

