@ARTICLE{10.3389/fmed.2025.1732805,
	author = {Fan Z and Hai W and Xianyi Z and Baozhao X and Jichun Y},
	title = {Advancements in understanding neuropsychiatric lupus: deciphering immune heterogeneity with single-cell resolution.},
	journal = {Front Med (Lausanne)},
	year = {2026},
	abstract = {Neuropsychiatric Systemic Lupus Erythematosus (NPSLE) represents one of the most severe and enigmatic manifestations of SLE, contributing significantly to disease morbidity and mortality. Its clinical presentation is profoundly heterogeneous, encompassing 19 distinct syndromes that pose considerable diagnostic and therapeutic challenges. While historical estimates of its prevalence varied widely, contemporary prospective studies suggest that approximately 56% of SLE patients experience a neuropsychiatric event, with 30-50% of these events being directly attributable to SLE-related pathogenic mechanisms. A comprehensive understanding of its multifactorial pathogenesis is critical for developing targeted therapies. The pathogenesis of NPSLE is an integrated neuroimmune process initiated by the disruption of the blood-brain and blood-CSF barriers. This breach permits peripheral autoimmune mediators-including pathogenic autoantibodies (e.g., anti-NMDAR, anti-ribosomal P), pro-inflammatory cytokines (e.g., Type I IFN, IL-6), and innate immune cells such as neutrophils forming Neutrophil Extracellular Traps (NETs)-to enter the central nervous system (CNS). Within the CNS, these insults trigger a robust response from resident glial cells. Microglia polarize to a pro-inflammatory M1 phenotype, driving neuroinflammation and pathological synaptic stripping, while astrocytes transition to a neurotoxic A1 phenotype, losing their neurosupportive functions. These inflammatory pathways are intricately linked with an ischemic/thrombotic pathway, often mediated by antiphospholipid antibodies, creating a complex pathogenic landscape. The adaptive immune system plays a crucial role in perpetuating the autoimmune attack within the CNS compartment. This involves the infiltration of pathogenic T cell subsets, as identified in animal models like the MRL/lpr strain, including T follicular helper (Tfh)-like cells in the choroid plexus and senescent/exhausted Eomes+ double-negative T cells within the brain parenchyma. Furthermore, the CNS can become an active site for B cell responses, supporting the intrathecal clonal expansion of B cells and plasma cells, leading to local production of pathogenic autoantibodies. Deconstructing this cellular and molecular complexity requires high-resolution technologies. Single-cell genomics (scRNA-seq, CITE-seq, scBCR-seq) and spatial transcriptomics are providing unprecedented insights into the specific cell types and states driving the disease. While direct analysis of human NPSLE brain tissue remains rare, a powerful framework is emerging from synthesizing mechanistic data from diverse animal models (e.g., MRL/lpr and NZB/W F1) with findings from human CSF in related neuroinflammatory conditions. The translation of these molecular insights into clinical practice is the ultimate goal. This research paves the way for moving beyond descriptive syndromic classifications toward a mechanism-based stratification using "immune endophenotypes." Such an approach promises to enhance biomarker discovery (e.g., NfL, GFAP, CXCL13) and guide the development of targeted therapies, such as Type I IFN receptor blockade and specific B cell-directed agents. By bridging high-resolution discovery with clinical reality, we can advance toward an era of precision medicine for the management of NPSLE.},
	doi = {10.3389/fmed.2025.1732805},
	pmid = {41608446},
	note = {PMC12835350}
}

@ARTICLE{10.1038/s41598-025-34652-6,
	author = {Nakamura T and Abe S and Oiwake T and Hayashi A},
	title = {Retinal structure and function recovery over five years in Vogt-Koyanagi-Harada disease using adaptive optics and microperimetry.},
	journal = {Sci Rep},
	year = {2026},
	abstract = {Vogt-Koyanagi-Harada (VKH) disease recovery patterns remain inadequately characterized over extended periods. This study evaluated retinal changes in VKH patients across 5 years using adaptive optics imaging and microperimetry. Twenty-five eyes from 13 patients were monitored longitudinally. Macular cone density gradually increased throughout the observation period but remained below healthy control levels. Eyes with pretreatment cystoid spaces initially showed lower cone density values, but this disparity disappeared after 3 years. Average threshold values improved consistently from baseline, while macular integrity values significantly decreased after 2 years. Cone density correlated significantly with retinal sensitivity. These findings indicate that with appropriate treatment, VKH disease demonstrates progressive improvement in both retinal structure and function over time, though complete structural recovery may not occur. Pretreatment cystoid spaces influence early outcomes but do not significantly affect long-term recovery. SUPPLEMENTARY INFORMATION: The online version contains supplementary material available at 10.1038/s41598-025-34652-6.},
	doi = {10.1038/s41598-025-34652-6},
	pmid = {41559144},
	note = {PMC12868689}
}

@ARTICLE{10.1167/iovs.67.1.7,
	author = {Oshiro A and Imanaga N and Terao N and Yamanari M and Totani K and Sugiyama S and Koizumi H},
	title = {Evaluation of Melanin Changes in Acute Vogt-Koyanagi-Harada Disease Using Polarization-Sensitive Optical Coherence Tomography.},
	journal = {Invest Ophthalmol Vis Sci},
	year = {2026},
	abstract = {PURPOSE: To examine melanin changes in the RPE and choroid during the acute phase of Vogt-Koyanagi-Harada (VKH) disease using polarization-sensitive optical coherence tomography (PS-OCT). METHODS: This study included 15 eyes of 8 patients with new-onset VKH disease and 5 eyes of 3 patients with posterior scleritis. PS-OCT captured a 12 × 12 mm area centered on the fovea, and en face images were created for the RPE and choroid. Polarimetric entropy within a 6-mm diameter circle centered on the fovea was calculated and compared between groups. RESULTS: Choroidal polarimetric entropy was significantly lower in eyes with VKH disease than in those with posterior scleritis at baseline (0.296 ± 0.047 vs. 0.392 ± 0.050; P = 0.005; r = 0.64; 95% confidence interval, 0.42-0.74). One month after starting treatment, eyes with VKH disease showed a significant increase in choroidal polarimetric entropy (0.296 ± 0.047 to 0.350 ± 0.075; P = 0.001; r = 0.85; 95% confidence interval, 0.61-0.95), whereas no significant change was observed in eyes with posterior scleritis. RPE polarimetric entropy showed no significant changes between baseline and 1 month, with no differences between groups. CONCLUSIONS: PS-OCT revealed that choroidal melanin density decreased during the acute phase of VKH disease and significantly increased after treatment. PS-OCT provides a noninvasive method for observing melanin dynamics in VKH disease and aids in differentiating it from posterior scleritis. PS-OCT could offer valuable insights into the pathology of VKH disease and its potential implications for management.},
	doi = {10.1167/iovs.67.1.7},
	pmid = {41533903 [Indexed for MEDLINE]},
	note = {PMC12786395}
}

@ARTICLE{10.1016/j.ajo.2026.01.004,
	author = {Mohan N and Srivastava SK and Schulgit MJ and Hajj-Ali RA and Kaelber DC and Sharma S},
	title = {Exploring the Association Between Autoimmune and Inflammatory Diseases and Uveitis.},
	journal = {Am J Ophthalmol},
	year = {2026},
	abstract = {OBJECTIVE: To evaluate the association between immune-mediated inflammatory diseases (IMIDs) and uveitis. DESIGN: Retrospective cohort and case-control study using electronic health record data. METHODS: The study included patients diagnosed with uveitis and/or one of the following 12 IMIDs: rheumatoid arthritis (RA), systemic lupus erythematosus (SLE), sarcoidosis, scleroderma, inflammatory bowel disease (IBD), multiple sclerosis (MS), ankylosing spondylitis, psoriasis, juvenile idiopathic arthritis (JIA), and giant cell arteritis (GCA), anti-neutrophil cytoplasmic antibody (ANCA)-associated vasculitis, and other systemic vasculitis. Controls were patients without prior uveitis diagnosis or any IMIDs. The risk of developing uveitis in patients with each IMID, the odds of prior IMID diagnoses among patients with uveitis, and the risk of developing an IMID following a uveitis diagnosis were calculated. The main outcome measures were the risk ratio (RR) and odds ratio (OR) estimates with 95% confidence intervals for associations between IMIDs and uveitis. RESULTS: Patients with all 12 IMIDs had a significantly increased risk of developing uveitis. The highest risks were observed in ankylosing spondylitis (RR = 7.71, 95% CI = 5.84-10.19), JIA (RR = 5.13, 95% CI = 3.51-7.49), and systemic vasculitis (RR = 4.61, 95% CI = 3.73-5.69). Increased risk was also found in sarcoidosis (RR = 3.67, 95% CI = 3.02-4.47), GCA (RR = 3.24, 95% CI = 2.58-4.07), and ANCA vasculitis (RR = 3.18, 95% CI = 1.84-5.48). In addition, in patients with uveitis, both the odds of a prior IMID diagnosis and the risk of a future IMID diagnosis were significantly increased for all 12 IMIDs. CONCLUSIONS: IMIDs are strongly associated with uveitis, with significant bidirectional risk. Patients with uveitis should be monitored for potential IMID development, and those with IMIDs should undergo ophthalmologic evaluation when appropriate.},
	doi = {10.1016/j.ajo.2026.01.004},
	pmid = {41525816 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ajo.2025.12.031,
	author = {Feo A and Sarraf D},
	title = {En Face Optical Coherence Tomography and OCT Angiography in the Pathoanatomy of Inflammatory Macular Disease.},
	journal = {Am J Ophthalmol},
	year = {2026},
	abstract = {PURPOSE: To review the pivotal role of en face optical coherence tomography (OCT) and OCT angiography (OCTA) in elucidating the pathoanatomy, diagnostic markers, and clinical management of inflammatory macular diseases. These noninvasive modalities provide depth-resolved, layer-specific visualization of structural and vascular alterations, enhancing our understanding of disease mechanisms and facilitating monitoring of disease activity and therapeutic response. METHODS: This perspective article synthesizes recent advances in multimodal imaging (MMI) with emphasis on en face OCT and OCTA across the spectrum of posterior noninfectious and infectious uveitic disorders. Representative diseases include multiple evanescent white dot syndrome (MEWDS), punctate inner choroidopathy (PIC), and idiopathic multifocal choroiditis (iMFC), acute zonal occult outer retinopathy (AZOOR), acute posterior multifocal placoid pigment epitheliopathy (APMPPE) and its chronic variants, serpiginous choroiditis (SC), acute syphilitic posterior placoid chorioretinopathy (ASPPC), and Vogt-Koyanagi-Harada (VKH) disease. Imaging signatures were reviewed in relation to pathophysiology, differential diagnosis, and clinical management. RESULTS: En face OCT delineates disease-specific topographic patterns: "dots and spots" in MEWDS, hyperreflective plaques in PIC/iMFC, trizonal maps in AZOOR, sharply demarcated placoid lesions in APMPPE, geographic patterns in SC, and concentric hyperreflective "fingerprint" rings in VKH. OCTA provides complementary vascular insights, distinguishing preserved vs impaired choriocapillaris (CC) flow and revealing disease-driven ischemia. MEWDS typically demonstrates preserved CC perfusion, in contrast to the flow deficits of APMPPE, relentless placoid chorioretinitis, and SC. In PIC/iMFC, OCTA enables detection of inflammatory choroidal neovascularization (iCNV), while in ASPPC and VKH, it captures reversible or persistent CC flow voids following appropriate systemic therapy. Structural-vascular correlation permits differentiation between ischemic and nonischemic disorders, recognition of masquerades, and monitoring of subclinical disease activity. CONCLUSIONS: En face OCT and OCTA have redefined the diagnostic and management landscape of inflammatory macular diseases by providing rapid, reproducible, and layer-specific structural-vascular information. Their disease-specific signatures enhance accuracy, support treatment decisions, and improve monitoring of progression and complications such as inflammatory CNV. Integration of these tools into routine multimodal imaging protocols is essential, while future research should prioritize standardization of acquisition and interpretation criteria, quantitative biomarkers, and expanded use of widefield technologies to capture peripheral and longitudinal disease dynamics.},
	doi = {10.1016/j.ajo.2025.12.031},
	pmid = {41490810 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2025.1651923,
	author = {Xia Q and Sun D and Wan K and Liu C and Shu H and Wang M and Zhou T and Chen Y and Yang X and Li XF and Song B and Wang F},
	title = {Lactylation: the metabolic-immune hub in autoimmune diseases.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {In recent years, lactate modification, as an emerging post-translational modification mechanism, has attracted increasing attention for its role in the regulation of the immune system. Autoimmune diseases are a category of complex disorders characterized by abnormal attacks of the immune system on self-tissues. The limitations of traditional treatments have made the search for new therapeutic targets a hot topic in research. Lactate modification plays a significant role in the development and progression of autoimmune diseases. It can modulate the activation and function of T cells, B cells, macrophages, and dendritic cells, thereby influencing inflammatory and autoimmune responses. In diseases such as experimental autoimmune uveitis (EAU), rheumatoid arthritis (RA), and systemic lupus erythematosus (SLE), lactate modification is closely related to disease progression and can exert its effects by regulating key signaling pathways and cytokine networks. Research on lactate modification as a therapeutic target has also made certain progress, providing new ideas for the treatment of autoimmune diseases. However, there are still many challenges to be faced, such as the development of specific inhibitors, the evaluation of potential side effects, and the feasibility of clinical application. The important regulatory role of lactate modification in autoimmune diseases offers a new target for treatment. Future research needs to further explore its specific mechanisms in the immune system, optimize therapeutic strategies, and assess its clinical application prospects, in order to bring breakthrough progress to the treatment of autoimmune diseases.},
	doi = {10.3389/fimmu.2025.1651923},
	pmid = {41488662 [Indexed for MEDLINE]},
	note = {PMC12756412}
}

@ARTICLE{10.3389/fphar.2025.1678663,
	author = {Ding H and Zhang S and Lin L and Zhang K},
	title = {Case Report: Tislelizumab-induced panuveitis: a report of two cases.},
	journal = {Front Pharmacol},
	year = {2025},
	abstract = {BACKGROUND: Tislelizumab, an increasingly utilized immunotherapy for a range of malignancies, can induce a rare ocular immune-related adverse event resembling Vogt-Koyanagi-Harada-like syndrome (VKHLS). Management of complication requires careful balancing with ongoing systemic anti-tumor therapy. CASE PRESENTATION: This report describes two cancer patients who developed severe bilateral vision loss following Tislelizumab treatment. Multimodal ocular imaging confirmed the diagnosis of immune checkpoint inhibitors (ICIs)-associated uveitis, specifically a VKHLS. Both patients were managed with discontinuation of Tislelizumab and local corticosteroid therapy-transcutaneous periocular injection of triamcinolone acetonide (TA) and topical steroid eye drops, without systemic corticosteroids. Their uveitis resolved rapidly, with recovery of visual acuity. CONCLUSION: Prompt Tislelizumab discontinuation combined with local corticosteroid therapy-transcutaneous periocular TA injections, and topical steroid eye drops may constitute an effective management strategy for ICIs-induced uveitis. This approach is particularly valuable for cancer patients in whom systemic corticosteroids are contraindicated or unsuitable.},
	doi = {10.3389/fphar.2025.1678663},
	pmid = {41487505},
	note = {PMC12758019}
}

@ARTICLE{10.1016/j.jare.2025.12.030,
	author = {Wen Y and Zhu L and Huang Z and Zhang G and Tian S and Peng Y and Zhang Y and Wu D and Chen X and Jiang G and Su W and Li H},
	title = {Single-Cell RNA sequencing identifies NAMPT as a potential therapeutic target in autoimmune uveitis.},
	journal = {J Adv Res},
	year = {2025},
	abstract = {INTRODUCTION: Autoimmune uveitis (AU) is an autoimmune disease of the eye that can lead to irreversible vision loss. Current therapies are limited by suboptimal efficacy and substantial side effects, highlighting the urgent need for the discovery of novel therapeutic targets. Nicotinamide phosphoribosyltransferase (NAMPT) is a key enzyme controlling the NAD+ salvage pathway and also exerts immunoregulatory and anti-inflammatory effects. However, its role in AU remains unclear. OBJECTIVE: To investigate NAMPT's effects on AU and underlying mechanisms. METHODS: Single-cell RNA sequencing (scRNA-seq) was performed on cervical draining lymph node (CDLN) cells from normal, experimental autoimmune uveitis (EAU), and NAMPT inhibitor-treated EAU mice. The influence of NAMPT inhibition on immune cell subsets, transcriptional programs, and intercellular communication networks was comprehensively analyzed. Additionally, scRNA-seq was performed on peripheral blood mononuclear cells (PBMCs) collected from Vogt-Koyanagi-Harada (VKH) disease patients and healthy controls (HC) to assess NAMPT expression and its modulation in human CD4+ T cells. In vivo and in vitro experiments, flow cytometry, and adoptive transfer experiments confirmed NAMPT's role in uveitis. RESULTS: NAMPT inhibition significantly ameliorated the clinical and histopathological manifestations of EAU. scRNA-seq revealed that NAMPT blockade reshaped immune cell composition and reversed disease-associated transcriptional programs, particularly within CD4+ T cells. It suppressed pro-inflammatory T helper (Th)-17 and Th1 responses while promoting regulatory T cell (Treg) populations. Mechanistically, NAMPT inhibition modulated the Th17/Treg balance by downregulation of Hif1α expression. In VKH patients, CD4+ T cells exhibited elevated NAMPT expression, which led to increased Th17 and Th1 cells and reduced Tregs. NAMPT knockdown reproduced the protective phenotype observed with FK866 treatment, suggesting a conserved NAMPT-Hif1α axis in human uveitis. CONCLUSIONS: Inhibiting NAMPT can reverse the imbalance of effector T (Teff)/Treg cells by suppressing the expression of Hif1α in CD4+T cells, thereby effectively alleviating the symptoms of EAU. Therefore, NAMPT might be a potential target for AU.},
	doi = {10.1016/j.jare.2025.12.030},
	pmid = {41475661}
}

@ARTICLE{10.3390/ph18121848,
	author = {Lee J and Chung YR and Kim HR and Song JH},
	title = {Efficacy of Tumor Necrosis Factor-α Inhibitor Adalimumab in Chronic Recurrent Vogt-Koyanagi-Harada Disease.},
	journal = {Pharmaceuticals (Basel)},
	year = {2025},
	abstract = {Background/Objectives: Vogt-Koyanagi-Harada (VKH) disease is a bilateral granulomatous panuveitis that can progress to a chronic, relapsing phase. Patients refractory or intolerant to systemic corticosteroids and conventional immunomodulatory therapy pose a major therapeutic challenge, as persistent inflammation can lead to cumulative ocular damage and permanent vision loss. This study assessed the efficacy of tumor necrosis factor-α (TNF-α) inhibitor adalimumab in chronic recurrent VKH disease. Methods: We retrospectively reviewed 16 eyes from 8 patients with chronic recurrent VKH disease who had persistent inflammation despite treatment with corticosteroids and conventional immunomodulatory therapy, and subsequently received adalimumab. Primary outcomes were changes in subfoveal choroidal thickness (SFCT) and systemic corticosteroid dose reduction. Secondary outcomes included visual acuity, inflammatory parameters (anterior chamber cell, flare, and vitreous haze), and central macular thickness (CMT). All outcomes were compared between baseline and 6 months after adalimumab initiation using the Wilcoxon signed-rank test. Results: Mean patient age was 47.6 years and mean follow-up was 31.8 months. SFCT decreased from 326.7 ± 129.1 μm to 231.6 ± 72.9 μm at 6 months (p < 0.001). Systemic steroid dose decreased from 14.7 ± 14.0 mg to 4.1 ± 3.8 mg (p = 0.027). Mean annualized relapse rate decreased from 3.61 to 0.08 episodes/year (p = 0.012). Anterior chamber cell grade decreased from 0.81 ± 0.66 to 0.09 ± 0.20 (p < 0.001). Visual acuity, flare, vitreous haze, and CMT showed no significant change. No serious adverse events occurred. Conclusions: TNF-α inhibition with adalimumab appears effective as steroid-sparing therapy for controlling recurrent inflammation and reducing steroid dependence in patients with chronic recurrent VKH disease refractory to conventional treatment.},
	doi = {10.3390/ph18121848},
	pmid = {41471337},
	note = {PMC12736142}
}

@ARTICLE{10.3389/fimmu.2025.1689498,
	author = {Li P and Wang Q and Yang Y and Ding Z},
	title = {Autoimmune thyroid disease and human health: a systematic review of Mendelian randomization studies.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {We systematically summarized current Mendelian randomization (MR) evidence on the causal relationships between autoimmune thyroid disease (AITD) and a wide range of human health outcomes. Original MR studies related to AITD published up to March 1, 2025, were retrieved from PubMed and Embase. For studies investigating the same exposure-outcome associations, meta-analyses were performed to synthesize the evidence after excluding overlapping samples where applicable. The methodological quality of the included studies was assessed using the STROBE-MR checklist. A total of 123 MR publications met the inclusion criteria. MR analyses indicated that AITD significantly increased the risk of coronary atherosclerosis, deep venous thrombosis, chronic obstructive pulmonary disease, major depression, diabetic neuropathy, carpal tunnel syndrome, neuromyelitis optica spectrum disorder, diabetic retinopathy, childhood absence epilepsy, rheumatoid arthritis, systemic lupus erythematosus, psoriatic arthritis, inflammatory bowel disease, crohn's disease, vitiligo, myasthenia gravis, alopecia areata, type 1 and type 2 diabetes, sarcoidosis, frozen shoulder, drug eruptions, cataract, early age-related macular degeneration, pernicious anemia, Helicobacter pylori infection, temporomandibular disorders, migraine, frailty, primary biliary cholangitis, knee osteoarthritis, gout, and osteoporosis, while decreasing the risk of lung cancer, polyneuropathies, allergic rhinitis, telomere length, and serum vitamin A levels. The included MR studies were of high methodological quality and provided robust evidence supporting the bidirectional relationships between AITD and various health outcomes. These findings emphasize the importance and necessity of preventing and managing AITD while offering new perspectives and directions for future research on its prevention and treatment. SYSTEMATIC REVIEW REGISTRATION: https://www.crd.york.ac.uk/prospero/, identifier CRD42023469038.},
	doi = {10.3389/fimmu.2025.1689498},
	pmid = {41425574 [Indexed for MEDLINE]},
	note = {PMC12711731}
}

@ARTICLE{10.1002/art.70022,
	author = {Li BM and Hung JH and Yang PC and Lin SJ and Lai EC and Weng MY},
	title = {Weighing Dose-Related Benefits and Risks of Hydroxychloroquine Treatment in Patients With Systemic Lupus Erythematosus.},
	journal = {Arthritis Rheumatol},
	year = {2025},
	abstract = {OBJECTIVE: To weigh higher-dose hydroxychloroquine (HCQ; ≥400 mg/day) and lower-dose HCQ (<400 mg/day) for effectiveness and safety among patients with systemic lupus erythematosus (SLE). METHODS: This nationwide study retrieved data from Taiwan's National Health Insurance Research Database from 2010 to 2021. We included patients with SLE aged over 10 years and initiating HCQ who had no other systemic autoimmune disease at baseline and no historical outcomes of interest. Patients were classified into higher-dose (≥400 mg/day) or lower-dose (<400 mg/day) treatment strategies based on the dosage of their first HCQ prescription. The outcomes were coronary artery disease (CAD), ischemic stroke, venous thromboembolism (VTE), end-stage renal disease, malignancy, and HCQ retinopathy. RESULTS: Eight hundred seventy-eight (3.77%) patients taking higher-dose HCQ and 22,405 (96.22%) taking lower-dose HCQ were included. After inverse probability weighting, higher-dose HCQ was associated with lower risks of CAD (hazard ratio [HR] 0.86, 95% confidence interval [CI] 0.80-0.93) and VTE (HR 0.40, 95% CI 0.33-0.49). We found no dose-related difference in the risk of ischemic stroke, end-stage renal disease, malignancy, and HCQ retinopathy through a mean follow-up of six years, except for the HCQ retinopathy among patients with SLE aged over 45 years (HR 1.87, 95% CI 1.45-2.42). CONCLUSION: For patients with SLE, higher-dose HCQ improves effectiveness, with reduced risks of CAD and VTE. There was no dose-related difference in the risk of HCQ retinopathy for patients with SLE aged younger than 45 years. Our study emphasizes the need for weighing the benefits and risks of optimal HCQ dosage in managing SLE.},
	doi = {10.1002/art.70022},
	pmid = {41423344}
}

@ARTICLE{10.14336/AD.2025.1221,
	author = {Ma H and Li S and Le Y and Stanford D and Freeman WM and Ding XQ},
	title = {Single Cell RNAseq Analysis of Thyroid Hormone Effects on Retinal Glial Cells.},
	journal = {Aging Dis},
	year = {2025},
	abstract = {Thyroid hormone (TH) signaling regulates cellular metabolism and stress response in the retina. Increased TH levels in circulation are associated with a higher incidence of age-related macular degeneration. Furthermore, stimulation of TH signaling induces retinal degeneration in mice, which is accompanied by the activation of retinal glial cells. Here, we investigated the transcriptional changes induced by triiodothyronine (T3) in retinal glial cells using single-cell RNA sequencing (scRNAseq) and bioinformatic analyses. One-month-old C57BL/6 mice were given T3 (20 μg/ml in drinking water) for four weeks, after which their retinal cells were collected to assess viability and undergo scRNAseq. The resulting data were analyzed using the Seurat package, visualized by the Loupe Browser, and Ingenuity Pathway Analysis. Analyses of differentially expressed genes (DEGs) in Müller cells, astrocytes, and microglia revealed significant enrichment in pathways associated with stress, immune response, and degeneration. Müller cells exhibited upregulation of mitochondrial dysfunction, acute-phase response, and sirtuin signaling pathways. Astrocytes displayed downregulation of synaptogenesis, neurovascular coupling, cAMP response elements, and calcium signaling. Microglia showed upregulation of coordinated lysosomal expression and regulation signaling, systemic lupus erythematosus in T cells, and multiple sclerosis signaling, and downregulation of actin-binding Rho activating signaling, retinoic acid receptor activation signaling, and IL-17 signaling. The distinct and overlapping transcriptional responses suggest that each retinal glial cell type plays a specific and coordinated role in adapting to stress. This study offers new insights into TH-induced retinal stress and degeneration at the transcriptional and pathway-level responses of retinal glial cells.},
	doi = {10.14336/AD.2025.1221},
	pmid = {41400582}
}

@ARTICLE{10.3390/ijms262311744,
	author = {Luboń W, Luboń M, Agaś-Lange A and Dorecka M},
	title = {Systemic Lupus Erythematosus: Ophthalmological Safety Considerations of Emerging and Conventional Therapeutic Agents.},
	journal = {Int J Mol Sci},
	year = {2025},
	abstract = {Systemic lupus erythematosus (SLE) is a chronic multisystem autoimmune disorder in which ocular involvement represents a clinically significant yet frequently underrecognized contributor to morbidity. Ocular manifestations in SLE may arise from disease activity itself, but also as adverse effects of long-term pharmacological therapy. With the advent of targeted immunomodulatory agents, the therapeutic landscape of SLE has expanded beyond conventional drugs such as hydroxychloroquine and corticosteroids toward biologics and small molecules designed to interfere with specific immunological pathways. These advances have improved systemic disease control and survival; however, their ophthalmological safety profiles remain only partially defined. This review synthesizes current evidence on ocular adverse events associated with both traditional and emerging SLE therapies. Established agents, particularly hydroxychloroquine and corticosteroids, are consistently linked to complications including retinopathy, posterior subcapsular cataracts, steroid-induced glaucoma, and central serous chorioretinopathy. In contrast, recently approved or investigational therapies-such as belimumab, anifrolumab, voclosporin, dual BAFF/APRIL inhibitors, rituximab, JAK inhibitors, CD40/CD40L blockade, CD38 inhibition, and mesenchymal stromal cell-based strategies-have limited but evolving safety data, with potential ocular adverse events spanning inflammatory, vascular, neuro-ophthalmic, and structural domains. Although ocular complications appear infrequent in clinical trials, underdetection in real-world practice and insufficient long-term monitoring may underestimate their true incidence. These findings highlight the need for systematic ophthalmological surveillance in patients receiving immunomodulatory therapies for SLE. Early recognition and timely management of ocular toxicity are crucial to safeguarding visual function and optimizing long-term therapeutic outcomes in this vulnerable patient population.},
	doi = {10.3390/ijms262311744},
	pmid = {41373894 [Indexed for MEDLINE]},
	note = {PMC12693600}
}

@ARTICLE{10.1093/brain/awaf458,
	author = {Akada M and Hata M and Miyake M and Ishihara K and Muraoka Y and Morooka S and Tamura H and Tsujikawa A},
	title = {Natural experiment on neuroinflammatory disease incidence and infection links pre- and post-COVID-19.},
	journal = {Brain},
	year = {2026},
	abstract = {Infections are recognized triggers for several neuroinflammatory disorders. The coronavirus disease 2019 (COVID-19) pandemic's non-pharmaceutical interventions sharply curtailed pathogen exposure, creating a natural experiment to test infection-disease links. Using Japan's National Claims Database, we first validated the nationwide decline with two strictly infection-dependent conditions-epidemic keratoconjunctivitis and influenza-associated encephalopathy-whose monthly incidences fell by >60% after April 2020. Next, we applied an interrupted time series design, a causal-inference method for longitudinal data, to nine immune-mediated inflammatory diseases. Unsupervised clustering of model-derived level and slope changes identified three data-driven clusters. The first cluster, comprising Guillain-Barré syndrome and acute disseminated encephalomyelitis, showed large, statistically significant level reductions (P < 0.001), particularly in women, consistent with infection-susceptible pathophysiology. The second cluster, including myasthenia gravis and optic neuritis, exhibited transient declines followed by significant positive post-intervention slopes (P < 0.001), suggesting deferred diagnosis, treatment interruption or immune rebound. The third cluster, consisting of sarcoidosis, neuromyelitis optica, multiple sclerosis, Vogt-Koyanagi-Harada disease and Behçet's disease, remained stable, suggesting limited or complex infectious links. These data-driven trajectories mirror clinical pathophysiology and demonstrate that reduced pathogen exposure affects neuroinflammatory disease onset to varying degrees. This framework supports infection-related risk stratification, preventive strategies and continuity planning in neuroimmunology practice.},
	doi = {10.1093/brain/awaf458},
	pmid = {41359492 [Indexed for MEDLINE]}
}

@ARTICLE{10.1186/s13040-025-00499-w,
	author = {Basharat Z and Ogaly HA and Al-Zahrani FAM and Wei CR and Hassan SS and Salman M and Islam M and Ahmed I and Waheed Y and Kim S},
	title = {Bioinformatics analysis of Rickettsia typhi autoimmune associations and screening of Streptomyces-derived inhibitors.},
	journal = {BioData Min},
	year = {2025},
	abstract = {BACKGROUND: Rickettsia typhi is the causative agent of epidemic murine typhus and Rocky Mountain spotted fever. The infection can affect multiple vital organs, including the heart, lungs, kidneys, and brain. Doxycycline is the recommended treatment but inflammation, mal-response, and drug resistance may arise. No natural product inhibitors have been reported against this bacterium. AIM: The objective of this study was to establish a potential connection between autoimmune disorders triggered by R. typhi, identify therapeutic targets within its core proteome, and explore novel natural product inhibitors from Streptomyces spp. that could potentially inhibit it. METHODOLOGY: Complete proteomes of four publicly available R. typhi strains were used for pan-proteomic analysis. The fni gene product (Isopentenyl pyrophosphate isomerase) was selected as the potential drug target. Molecular docking of 607 Streptomyces-derived metabolites was performed, with top hits validated using DiffDock and Vinardo scoring. Additionally, the Absorption, Distribution, Metabolism, Excretion, and Toxicity properties of the leading compounds were assessed via pkCSM, and formulation characteristics optimized using FormulationAI. RESULTS: Out of the 803 core proteins, associations between 14 proteins were mined for autoimmune diseases (including psoriasis, rheumatoid arthritis, optic atrophy, uveitis, even-plus syndrome, Sjogren syndrome, inflammatory bowel disease, allergic rhinitis, systemic lupus erythematosus, sclerosis, Stevens-Johnson syndrome, toxic epidermal necrolysis, colitis etc.). 17 core proteins were predicted as druggable. ZINC01482946 demonstrated the strongest inhibitory potential, as confirmed by DiffDock scoring, convolutional neural network-based ranking, and Vinardo scoring. It demonstrated a stable configuration and exhibited a favorable pharmacokinetic profile, with bioavailability enhanced through cyclodextrin complexation. CONCLUSION: To the best of our knowledge, this is the first report identifying human autoimmune associations with R. typhi and natural product inhibitors targeting the pathogen. ZINC01482946 shows potential as an effective inhibitor of R. typhi, while SBE-β-CD appears to be a promising cyclodextrin for improving its solubility and bioavailability. CLINICAL TRIAL NUMBER: Not applicable.},
	doi = {10.1186/s13040-025-00499-w},
	pmid = {41316447},
	note = {PMC12661794}
}

@ARTICLE{10.1016/j.ijbiomac.2025.149013,
	author = {Sijilmassi O},
	title = {Collagen IV and laminin-1 as key macromolecules in ocular structure and pathology: A review.},
	journal = {Int J Biol Macromol},
	year = {2025},
	abstract = {The extracellular matrix (ECM), particularly the basement membrane (BM), is critical for the structural organization and functionality of ocular tissues. Among its core components, type IV collagen and laminin-1 play central roles in cell adhesion, polarity, differentiation, and survival. These macromolecules are ubiquitously expressed in the cornea, lens, retina, and optic nerve, forming tissue-specific BMs that support development and homeostasis. In this review, findings on the spatial distribution and molecular roles of collagen IV and laminin-1 in the eye under physiological and pathological conditions, are summarized. Mutations in COL4A1, COL4A2, and laminin-encoding genes (LAMA1, LAMB1, LAMC1) are associated with a range of ocular disorders, including anterior segment dysgenesis, lens dystrophy, optic nerve hypoplasia, and retinal abnormalities. Furthermore, autoimmune responses targeting these BM proteins have been implicated in systemic diseases such as rheumatoid arthritis, systemic lupus erythematosus, systemic sclerosis, and Sjögren's syndrome, often leading to serious ocular complications. This review emphasizes the importance of ECM macromolecules in maintaining ocular integrity and highlights their potential as diagnostic biomarkers and therapeutic targets in both inherited and immune-mediated eye diseases.},
	doi = {10.1016/j.ijbiomac.2025.149013},
	pmid = {41237879 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.bcp.2025.117483,
	author = {Wu D and Gao Y and Wen Y and Zhang Y and Chen Y and Zhu L and Peng X and Pan Z and Huang D and Qin S and Li H and Su W},
	title = {Single-cell RNA sequencing reveals beneficial mechanisms of Exendin-4 in autoimmune uveitis.},
	journal = {Biochem Pharmacol},
	year = {2026},
	abstract = {Autoimmune uveitis (AU), a sight-threatening inflammatory eye disease, is a leading cause of irreversible vision loss. Current treatments are limited by suboptimal efficacy and significant complications, highlighting the need for new therapeutic strategies. Exendin-4 (Ex-4), a glucagon-like peptide-1 receptor agonist primarily used for glycemic control and weight management, has recently shown potential anti-inflammatory effects. However, its role in AU remains unexplored. Here, we demonstrated that Ex-4 treatment effectively alleviated EAU symptoms. Our analysis revealed that Ex-4 partially reversed both the proportional changes and transcriptional alterations in immune cell populations during EAU. Bioinformatic analysis showed that Ex-4 suppressed the EAU-induced upregulation of Pim1 expression. Subsequent experiments revealed that Ex-4 restored the effector T (Teff) /regulatory T (Treg) cell balance via the suppression of the PIM1-protein kinase B (AKT)-Forkhead box O1 (FOXO1) pathway.These effects were further observed in patients with Vogt-Koyanagi-Harada disease (VKH), a human uveitis. Our study provides valuable insights into Ex-4- mediated immune modulation and highlights potential therapeutic targets for autoimmune uveitis.},
	doi = {10.1016/j.bcp.2025.117483},
	pmid = {41173056 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2025.1640455,
	author = {Gehrke M and Thurau S and Wildner G},
	title = {Case Report: Treating one autoimmune disease induces another: the paradox of TNF-alpha inhibitor therapies.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {Although TNF-α-blockade is an approved treatment for several autoimmune diseases there are cases of paradoxical induction of autoimmunity appearing under anti-TNF therapy, even of diseases that are usually treated with TNF-blockers. The case of a patient with hidradenitis suppurativa (HS) from the department of dermatology was referred to our eye hospital due to blurred vision and subsequently diagnosed Vogt-Koyanagi-Harada-like disease (VKHLD) as an adverse effect of her long-term adalimumab therapy. A novel antibody targeting IL-17, bimekizumab, was introduced as a therapy for her skin disease with concomitant improvement of her ocular symptoms. In contrast to formerly tested anti-IL-17-antibodies with moderate therapeutic effect on uveitis this novel antibody targets both, IL-17A and -F and is thus expected to be more effective. This case inspired us to further analyze the paradoxical immune mechanisms of TNF-α blockade that might induce autoimmunity and the pathomechanisms of HS and VKHD, revealing an interplay of TNF-α and IL-17 signaling pathways. This led us to a hypothesis explaining the paradox of inducing autoimmunity by TNF-blockade in context with IL-17-mediated autoimmune diseases and an explanation why VKHD should be treated with anti-IL-17A/F rather than with anti-TNF-α.},
	doi = {10.3389/fimmu.2025.1640455},
	pmid = {41142785 [Indexed for MEDLINE]},
	note = {PMC12549613}
}

@ARTICLE{10.1186/s12967-025-07118-6,
	author = {Chen L and Sun L and Meng L and Wang C and Chen Y},
	title = {Conjunctival and retinal microvascular loss in systemic lupus erythematosus: a swept-source OCTA study.},
	journal = {J Transl Med},
	year = {2025},
	abstract = {PURPOSE: This study aimed to characterize conjunctival and retinal microvascular alterations in Systemic lupus erythematosus (SLE) using swept-source optical coherence tomography angiography (SS-OCTA), and to evaluate their correlation with systemic clinical manifestations. METHODS: This cross-sectional study enrolled 32 SLE patients and 32 age, sex, and spherical equivalent matched controls. Participants underwent swept-source OCTA imaging of nasal and temporal conjunctiva (16 × 12 mm scans) and macula (6 × 6 mm scans). Vessel density of conjunctival vessel, superficial vascular plexus (SVP), and deep vascular plexus (DVP) were quantified using automated segmentation. Correlation analyses were conducted to evaluate the association between conjunctival and retinal vascular densities, as well as their relationships with clinical parameters of systemic involvement and disease activity. RESULTS: SLE patients showed significant reductions in nasal (45.0% vs. 60.1%, p < 0.001) and temporal (51.8% vs. 60.5%, p = 0.009) conjunctival vascular density, alongside pan-retinal DVP attenuation (p < 0.05). Combined nasal conjunctival and retinal nasal DVP analysis yielded high diagnostic accuracy (AUC 0.897). Microvascular loss was independent of organ involvement or disease activity (p > 0.05). CONCLUSIONS: SLE is associated with significant reductions in conjunctival and retinal DVP vascular density. Combined multimodal SS-OCTA analysis achieved superior diagnostic accuracy, with microvascular loss independent of disease activity or organ-specific involvement, suggesting systemic microvascular injury as a unifying SLE feature. Conjunctival-retinal vascular metrics may serve as potential new biomarkers for SLE.},
	doi = {10.1186/s12967-025-07118-6},
	pmid = {41068946 [Indexed for MEDLINE]},
	note = {PMC12512552}
}

@ARTICLE{10.3390/diagnostics15172154,
	author = {Ahn SJ},
	title = {Resolved Central Serous Chorioretinopathy Mimicking Hydroxychloroquine Toxicity: A Case Series and Literature Review.},
	journal = {Diagnostics (Basel)},
	year = {2025},
	abstract = {Background and Clinical Significance: Central serous chorioretinopathy (CSCR) and hydroxychloroquine (HCQ) retinopathy can both cause outer retinal changes in systemic lupus erythematosus (SLE) patients treated with HCQ and corticosteroids. Differentiating between transient steroid-induced CSCR and irreversible HCQ toxicity is critical to avoid unnecessary discontinuation of essential therapy. Case Presentation: Three female SLE patients (ages 47, 41, and 37) on long-term HCQ (25, 9, and 6 years, respectively) and recent or ongoing low-dose prednisolone presented with unilateral OCT findings, parafoveal or pericentral photoreceptor defects, with the fellow eye unaffected. Review of clinical history and serial imaging revealed transient subretinal fluid in all cases, associated with recent corticosteroid use or dose escalation. Subsequent tapering or cessation of steroids led to resolution of the fluid, and earlier OCT scans confirmed normal outer retinal morphology, indicating that these changes were residual effects of resolved CSCR rather than HCQ toxicity. In Cases 1 and 2, the best-corrected visual acuity (BCVA) in the affected eye declined from 20/22 to 20/40 during the CSCR episode and improved to 20/30 and 20/25, respectively, after subretinal fluid resolution. In Case 3, by contrast, BCVA remained stable at 20/20 throughout the pre-, during-, and post-CSCR periods. Conclusions: Resolved CSCR can mimic HCQ retinopathy. These cases emphasize the importance of detailed medication history, serial multimodal retinal imaging, and comparison with prior and fellow-eye scans to distinguish resolved CSCR from HCQ retinopathy. Such thorough evaluation and careful differential diagnosis help ensure appropriate management-avoiding unnecessary HCQ discontinuation while protecting both ocular and systemic health.},
	doi = {10.3390/diagnostics15172154},
	pmid = {40941642},
	note = {PMC12428736}
}

@ARTICLE{10.3389/fimmu.2025.1646850,
	author = {Jin D and Liu X and Wang Y and Fang L and Nie W and Li C and Li SG and Li M},
	title = {Case Report: Concurrent retinal vasculitis and optic neuritis in systemic lupus erythematosus.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {Systemic lupus erythematosus (SLE) is a multisystem autoimmune disease that can affect the ocular system, with retinal vasculitis and optic neuritis being rare but serious manifestations. We present a case of a 26-year-old female with newly diagnosed SLE who developed both retinal vasculitis and optic neuritis, leading to progressive visual impairment. She was successfully treated with methylprednisolone and rituximab, achieving significant visual recovery. A review of existing literature highlights the diagnostic challenges, pathophysiology, and optimal treatment strategies for such cases. Our findings emphasize the importance of early recognition and aggressive immunosuppressive therapy in improving patient outcomes.},
	doi = {10.3389/fimmu.2025.1646850},
	pmid = {40901471 [Indexed for MEDLINE]},
	note = {PMC12399518}
}

@ARTICLE{10.7759/cureus.88626,
	author = {Azad MAK and Ahmed Alif A and Mallik NK and Nahar S and Ahmedullah AK and Hassan MM},
	title = {Bilateral Retinal Vasculitis in Systemic Lupus Erythematosus: A Case Series of Three Patients.},
	journal = {Cureus},
	year = {2025},
	abstract = {Systemic lupus erythematosus (SLE) is a long-term autoimmune disorder that affects multiple organ systems and presents with a broad spectrum of symptoms, ranging from mild, nonspecific complaints to severe, potentially life-threatening complications. It is commonly seen in females but may occur in males. Ocular involvement is common in SLE patients. These ophthalmic symptoms can develop during the course of the disease or may be the initial sign. Although rare, sudden vision loss due to retinal vessel involvement can be the first presentation of SLE. This case series highlights a rare manifestation of SLE bilateral retinal vasculitis as either the initial or subsequent presentation of the disease. The mean age with standard deviation of the patients in this series was 29.67±9.44​ years. Of the three patients, one was male and two were female. In one case, retinal vasculitis was the initial manifestation of SLE, while in the other two, it developed during the disease. All patients were treated with intravenous methylprednisolone (MP), followed by oral prednisolone at a dose of 1 mg/kg of body weight, in combination with monthly cyclophosphamide. Partial clinical improvement was observed in all cases. Retinal vasculitis, whether isolated or accompanied by involvement of other organs, should be considered in the differential diagnosis of visual disturbances in SLE patients. Early recognition and prompt treatment are critical to prevent irreversible retinal damage and complications.},
	doi = {10.7759/cureus.88626},
	pmid = {40861604},
	note = {PMC12373494}
}

@ARTICLE{10.3389/fphar.2025.1498814,
	author = {Li X and Zhang SQ and Wang KR and Wu SN and Wang MY and Chen CT and Dong N},
	title = {Chloroquine and hydroxychloroquine-related ocular adverse events in SLE treatment: a real-world disproportionality analysis based on FDA adverse event reporting system (FAERS).},
	journal = {Front Pharmacol},
	year = {2025},
	abstract = {OBJECTIVE: This study aimed to evaluate the risk of adverse events associated with chloroquine (CQ) and hydroxychloroquine (HCQ) in patients with systemic lupus erythematosus (SLE), using data from the U.S. Food and Drug Administration Adverse Event Reporting System (FAERS). METHODS: Disproportionality analysis was conducted using the Reporting Odds Ratio (ROR) to detect potential safety signals. Sensitivity analyses were performed to validate these signals, and the time to onset for each Preferred Term (PT) was assessed. RESULTS: Between 2004 and 2024, a total of 2,575 adverse event reports related to HCQ or CQ use in patients with SLE were identified in the FAERS database, of which 437 involved ocular adverse events. The most frequently reported ocular conditions were cataract, macular degeneration, and glaucoma. Disproportionality analysis demonstrated strong associations between HCQ/CQ use and retinal degeneration (ROR = 28.5, 95%CI: 19.94-40.74), cystoid macular oedema (ROR = 12.46, 95%CI: 8.01-19.37), and optic atrophy (ROR = 6.55, 95%CI: 3.51-12.19). Sensitivity analyses, conducted after excluding SLE cases, indicated that all but one event (vitreous floaters) remained statistically significant, suggesting that these risks are more likely attributable to HCQ/CQ exposure than to the underlying disease. The time-to-onset analysis showed that cataract had the shortest average onset time (125.5 days), whereas retinal degeneration had the longest (937.5 days). CONCLUSION: The extensive clinical use of HCQ and CQ raises significant concerns regarding their ocular safety profile. This study provides real-world pharmacovigilance evidence supporting a substantial risk of ocular adverse events associated with HCQ/CQ use. Further mechanistic and prospective studies are warranted to elucidate the underlying pathophysiological pathways and to confirm these associations.},
	doi = {10.3389/fphar.2025.1498814},
	pmid = {40661080},
	note = {PMC12256490}
}

@ARTICLE{10.1038/s41598-025-08252-3,
	author = {Muto T and Sakamoto M and Machida S and Imaizumi S and Sekiryu T},
	title = {Predictive factors at initial visit for sunset glow fundus in Vogt-Koyanagi-Harada disease.},
	journal = {Sci Rep},
	year = {2025},
	abstract = {This study aimed to identify factors present at the initial visit for the development of sunset glow fundus (SGF) in Vogt-Koyanagi-Harada (VKH) disease. A total of 139 eyes from 70 naïve patients with acute VKH disease who underwent pulse steroid therapy were categorized into "SGF" and "non-SGF" groups based on fundus appearance at 12 months post-therapy. Multivariable analysis revealed that patients with meningismus (p = 0.004), incomplete type (p = 0.035), and probable type (p = 0.002) in older revised diagnostic criteria; ex-smoker (p = 0.016), and smoker (p = 0.010) status; high logarithmic best-corrected visual acuity (BCVA) (p < 0.001); high spherical equivalent (SE) (p = 0.005); shallow peripheral anterior chamber depth (ACD) (p < 0.001); narrow anterior chamber angle (ACA) (p = 0.015); increased pupil diameter (p < 0.001); and thicker cornea (p = 0.019) were associated with SGF. The optimal cut-off values for predicting SGF were identified as follows: logarithmic BCVA greater than 0.261, SE exceeding - 2.813 D, peripheral ACD less than 2.138 mm, ACA less than 40.55 °, pupil diameter exceeding 3.040 mm, and corneal thickness exceeding 579.500 μm. Patients with VKH disease who exhibit above risk factors require early and careful management.},
	doi = {10.1038/s41598-025-08252-3},
	pmid = {40624077 [Indexed for MEDLINE]},
	note = {PMC12234651}
}

@ARTICLE{10.3389/fimmu.2025.1511133,
	author = {Maitiyaer M and Zhang J and Li P and Jiang D and Li H and Lin Z and Ye Z and Huo Y and Huang W and Wang L and Liu Z and Yu S},
	title = {Belimumab-driven reductions in retinal microvascular density assessed by optical coherence tomography angiography: insights from systemic lupus erythematosus patients.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {BACKGROUND: Systemic lupus erythematosus (SLE) and lupus nephritis (LN) are associated with retinal microvascular changes that may reflect disease severity. This study aimed to evaluate differences in retinal vascular density (VD) between SLE patients with and without LN and assess the impact of rheumatological treatments on VD. METHODS: A cross-sectional study was conducted with 54 SLE patients (21 with LN, 33 without LN). Retinal VD was measured using optical coherence tomography angiography (OCTA), focusing on superficial and deep capillary plexus VD (SCP-VD and DCP-VD). The impact of Belimumab and other treatments was analyzed. Linear regression assessed the effects of LN status and treatments on DCP parafoveal VD. Lymphocyte subsets and cytokines were compared before and after Belimumab treatment. RESULT: LN patients showed significantly reduced macular vascular density compared with non-LN patients. Belimumab treatment (≥8 times) and hydroxychloroquine use (>5 years) were independently associated with lower DCP-VD, particularly in parafoveal areas. Cumulative doses of HCQ and glucocorticoids negatively correlated with VD. Linear regression showed a significant negative association between Belimumab treatment and parafoveal DCP-VD. Notably, Belimumab treatment led to reductions in serum CD19+ B cells and IL-10 levels. CONCLUSIONS: LN patients demonstrated distinct retinal microvascular alterations. Long-term Belimumab and HCQ treatments were associated with decreased retinal VD. Regular retinal health monitoring was recommended to prevent microvascular complications in SLE patients undergoing prolonged treatment.},
	doi = {10.3389/fimmu.2025.1511133},
	pmid = {40589745 [Indexed for MEDLINE]},
	note = {PMC12206790}
}

@ARTICLE{10.1016/j.xcrm.2025.102203,
	author = {Li T and Lin S and Guan Z and Zhou Y and Zeng D and Wang Z and Zhou Y and Fang P and Yu S and Liu R and Chen X and Wang YJ and Lu Y and Shu J and Qin Y and Wu Y and Wu Y and Wu C and Zhang S and Shen J and Li H and Chen T and Li J and Tham YC and Sabanayagam C and Zheng YF and Wagner SK and Keane PA and Wong TY and Dai R and Sheng B},
	title = {A deep learning system for detecting systemic lupus erythematosus from retinal images.},
	journal = {Cell Rep Med},
	year = {2025},
	abstract = {Systemic lupus erythematosus (SLE) is a serious autoimmune disorder predominantly affecting women. However, screening for SLE and related complications poses significant challenges globally, due to complex diagnostic criteria and public unawareness. Since SLE-related retinal involvement could provide insights into disease activity and severity, we develop a deep learning system (DeepSLE) to detect SLE and its retinal and kidney complications from retinal images. In multi-ethnic validation datasets comprising 247,718 images from China and UK, DeepSLE achieves areas under the receiver operating characteristic curve of 0.822-0.969 for SLE. Additionally, DeepSLE demonstrates robust performance across subgroups stratified by gender, age, ethnicity, and socioeconomic status. To ensure DeepSLE's explainability, we conduct both qualitative and quantitative analyses. Furthermore, in a prospective reader study, DeepSLE demonstrates higher sensitivities compared with primary care physicians. Altogether, DeepSLE offers digital solutions for detecting SLE and related complications from retinal images, holding potential for future clinical deployment.},
	doi = {10.1016/j.xcrm.2025.102203},
	pmid = {40570853 [Indexed for MEDLINE]},
	note = {PMC12281353}
}

@ARTICLE{10.3389/fimmu.2025.1602800,
	author = {Dai M and Huang C and Zhou M and Leong PY and Chen X},
	title = {Dual BLyS/APRIL targeted therapy with telitacicept in rituximab-refractory SLE-associated neuromyelitis optica spectrum disorder: a case report.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {This article presents a case of neuromyelitis optica spectrum disorder (NMOSD) secondary to systemic lupus erythematosus (SLE). The patient initially presented with unexplained nausea, vomiting, intractable hiccups, and significant bradycardia (48 bpm). Cranial and spinal MRI findings were unremarkable, while serum aquaporin-4 immunoglobulin G (AQP4-IgG) antibody titers were markedly elevated (1:320). Following exclusion of alternative etiologies through comprehensive serological and neuroimaging investigations, the diagnosis of area postrema syndrome (APS) was confirmed according to the 2015 International Panel for NMO Diagnosis (IPND) criteria as a distinct NMOSD subtype. The patient exhibited a rapid therapeutic response to high-dose glucocorticoid therapy and was discharged on maintenance methylprednisolone with adjunctive medications. At one-month follow-up, the patient reported progressive visual deterioration, prompting neuro-ophthalmologic evaluation. Clinical findings included mildly elevated intraocular pressure (22.2 mmHg OD, 22.5 mmHg OS), corrected refractive error, and abnormal visual evoked potentials (diminished amplitude with delayed waveforms). Other neuro-ophthalmic investigations revealed no abnormalities. Persistent AQP4-IgG seropositivity (titer 1:32) was noted, and gadolinium-enhanced MRI revealed focal signal abnormalities in the bilateral optic nerves, confirming optic neuritis. Intravenous rituximab therapy (500 mg every two weeks) was initiated; however, treatment was complicated by a generalized urticarial rash and pleuritic chest pain, with no significant improvement in visual acuity. The therapeutic regimen was subsequently modified to incorporate subcutaneous telitacicept (160 mg weekly) in combination with glucocorticoid taper protocol and hydroxychloroquine. After eight weeks of this combined therapy, marked visual improvement was observed. Follow-up gadolinium-enhanced MRI revealed decreased enhancement intensity in the corresponding optic nerve regions compared to baseline. The patient maintained clinical stability and continues long-term multidisciplinary surveillance. To our knowledge, this represents the third documented case validating the therapeutic efficacy of telitacicept in NMOSD. Our findings suggest that telitacicept may serve as a disease-modifying therapy for SLE patients with AQP4-IgG-seropositive NMOSD.},
	doi = {10.3389/fimmu.2025.1602800},
	pmid = {40491913 [Indexed for MEDLINE]},
	note = {PMC12146289}
}

@ARTICLE{10.1136/rmdopen-2024-005100,
	author = {Akbaba TH and Donmez-Demir B and Colpak AI and Akkaya-Ulum YZ and Ayan G and Erdener SE and Kadayifcilar S and Tuncer A and Kalyoncu U and Balci-Peynircioglu B and Dalkara T},
	title = {Serum immunoreactivity to neurofilament-medium shows high sensitivity and specificity in patients with Behçet disease.},
	journal = {RMD Open},
	year = {2025},
	abstract = {OBJECTIVES: Behçet disease (BD) is a complex vasculitis with both autoimmune and autoinflammatory features. Despite specific clinical features, no laboratory tests are available for the diagnosis of BD. We recently found that BD sera exhibited immunoreactivity against neurofilament medium protein (NF-M). This study aimed to replicate this finding in an independent cohort and to assess the specificity and sensitivity of NF-M immunoreactivity in serum samples obtained from BD, systemic lupus erythematosus (SLE), multiple sclerosis (MS), psoriatic arthritis (PsA) and non-Behçet uveitis (NBU) patients as well as healthy donors. METHODS: Serum samples from 76 patients (33 BD, 16 MS, 15 SLE, 9 PsA and 3 NBU) and 22 healthy donors (totalling 98 sera) were analysed. Mouse brain tissue sections were immunolabelled with the sera and examined using confocal microscopy. RESULTS: 97% (32/33) of BD patient sera exhibited a distinct fine filamentous staining pattern consistent with NF-M protein immunolabelling in axons, while sera from healthy controls and patients with SLE, MS, PsA and NBU showed no similar staining. Conversely, MS patient sera displayed a thick filamentous staining pattern attributed to oligodendrocytes and their myelin-forming processes. SLE patient sera intensely labelled all cell nuclei, conforming to immunoreactivity against nuclear antigens. CONCLUSIONS: These findings reveal the ubiquitous presence of NF-M immunoreactivity, reportedly cross-reacting with bacterial heat shock protein 65, in BD sera. This common and specific immunoreactivity may serve as a valuable tool for diagnosing BD. Additionally, the data confirm the unique potential of connective tissue-poor brain sections for identifying sero-immunoreactivity.},
	doi = {10.1136/rmdopen-2024-005100},
	pmid = {40447321 [Indexed for MEDLINE]},
	note = {PMC12128429}
}

@ARTICLE{10.1016/j.ajo.2025.05.030,
	author = {Browning DJ and Koonce DR and Mentreddy A and Punjabi O},
	title = {The Relationship of Hydroxychloroquine Retinopathy Progression to Stage at Cessation of Therapy.},
	journal = {Am J Ophthalmol},
	year = {2025},
	abstract = {PURPOSE: To examine the progression of hydroxychloroquine retinopathy (HCR) from the time of drug cessation to the last follow-up. DESIGN: Retrospective, consecutive case series SUBJECTS: 17 patients with HCR in whom drug was stopped and follow-up maintained. METHODS: Charts, visual fields, and retinal images were reviewed. Four ancillary studies were investigated: 10-2 visual fields (10-2 VF), multifocal electroretinography (mfERG), spectral domain optical coherence tomography (SD-OCT), and fundus autofluorescence (FAF) imaging. Retinopathy was graded as none, early, and advanced. MAIN OUTCOME MEASURES: Progression of retinopathy by the four test methods. RESULTS: Of the 17 patients, the numbers with at least two follow-up studies to allow comparison for progression were 17, 8, 16, and 9 for 10-2 VF, mfERG, SD-OCT, and FAF, respectively. Median follow-ups were 25, 22, 41, and 37 months for 10-2 VF, mfERG, SD-OCT, and FAF, respectively. The proportions of eyes with no retinopathy at drug cessation that progressed were 0/0, 3/5, 0/0, and 2/6 for 10-2 VF, mfERG, SD-OCT, and FAF, respectively. The proportions of eyes with early retinopathy that progressed were 4/6, 0/6, 2/15, and 3/7 for 10-2 VF, mfERG, SD-OCT, and FAF, respectively. The proportions of eyes with advanced retinopathy that progressed were 16/20, 0/5, 10/17, and 5/5 for 10-2 VF, mfERG, SD-OCT, and FAF, respectively. Progression of retinopathy was seen in cases without retinal pigment epithelium loss at the time of drug cessation. Not all ancillary studies show retinopathy at the time of diagnosis of HCR. Multifocal ERG shows a floor effect. Once response densities are low, detecting further progression of toxicity by this modality is not possible. A greater breadth of retinopathy progression is possible with 10-2 VF, SD-OCT, and FAF. CONCLUSIONS: If HC is stopped when decreased reflectivity of the parafoveal ellipsoid zone is detected by SD-OCT, the probability of retinopathy progression is low. The cut point at which progression of retinopathy is acknowledged to be likely despite drug cessation needs to be moved earlier to discontinuity of the ellipsoid zone.},
	doi = {10.1016/j.ajo.2025.05.030},
	pmid = {40447243 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ard.2025.04.006,
	author = {Nikolopoulos D and Sentis G and Kitsios I and Garantziotis P and Kapsala N and Pieta A and Flouda S and Manolakou T and Nikoloudaki M and Banos A and Chavatza K and Parodis I and Filia A and Bertsias G and Fanouriakis A and Boumpas DT},
	title = {Enhanced B cell and complement cascade gene signatures in patients with neuropsychiatric systemic lupus erythematosus.},
	journal = {Ann Rheum Dis},
	year = {2025},
	abstract = {OBJECTIVES: The management of neuropsychiatric systemic lupus erythematosus (NPSLE) remains challenging because of clinical heterogeneity and the complexity of pathophysiologic mechanisms involved. We sought to determine the molecular signature of NPSLE and its endotypes towards novel biomarkers and targeted therapies. METHODS: Whole-blood RNA sequencing from 308 patients with systemic lupus erythematosus (119 with NPSLE, 189 non-NPSLE) and 72-matched healthy controls (HCs) were performed. Supervised pathway enrichment analysis and unsupervised weighted gene coexpression network analysis were applied to distinguish clinically and molecularly defined NPSLE endotypes. RESULTS: Compared with HCs, patients with NPSLE demonstrated dysregulation of adaptive immune responses along with upregulation of interleukin (IL)-1, IL-6, IL-17, and IL-12/IL-23 signalling pathways. The comparison between NPSLE and non-NPSLE groups revealed a robust upregulation of complement cascade, DNA damage response, adaptive immunity, and IL-1 and IL-6 signalling. Furthermore, active NPSLE exhibited a strong autophagy signature. The B cell and complement cascade signatures exhibited a gradual upregulation across the non-NPSLE, inactive NPSLE, and active NPSLE subgroups. Within NPSLE, diffuse syndromes correlated positively with the oxidative phosphorylation module, while antiphospholipid antibody-positive NPSLE was not associated with specific signatures by unsupervised analysis. NPSLE endotypes such as cognitive dysfunction, seizures, psychosis, and optic neuritis were associated with distinct transcriptomic signatures namely IL-6 signalling and leukocyte migration, DNA damage response, inflammation, and type-I interferon, respectively. CONCLUSIONS: The clinical heterogeneity of NPSLE appears to be associated with molecular diversity, with certain endotypes or syndromes exhibiting distinct gene signatures. Upregulation of adaptive immune response and complement cascade suggests that complement inhibitors and B cell-targeted therapies could be further explored in NPSLE.},
	doi = {10.1016/j.ard.2025.04.006},
	pmid = {40348638 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2025.1543157,
	author = {Sturm B and Zang AL and Stingl J, Hasseli-Fräbel R and Fanouriakis A and Schwarting A and Geber C and Weinmann-Menke J and Alhaddad M and Triantafyllias K},
	title = {Ocular markers of microangiopathy and their possible association with cardiovascular risk in patients with systemic inflammatory rheumatic diseases: a systematic review.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {Individuals with autoimmune rheumatic diseases (ARDs) are at a higher cardiovascular (CV) risk due to systemic inflammation, which contributes to endothelial dysfunction, atherosclerosis, and structural changes in the vessel walls. Along with traditional CV risk factors like dyslipidaemia, arterial hypertension, obesity, and impaired glucose metabolism, these patients have a severe prognosis with higher CV morbidity and mortality rates. To date, there is limited data on the optimal CV screening methods for individuals with ARDs, as conventional risk algorithms may underestimate the influence of chronic inflammation. In comparison to macrovascular assessment methods, such as carotid-femoral pulse wave velocity and carotid sonography, microvascular changes, which may precede macrovascular disease, have been less investigated. The ocular microvasculature reflects systemic vascular health and can reveal early signs of CV disease. Changes in retinal vessels have been linked to an increased long-term risk of CV mortality and ischemic stroke in longitudinal studies of the general population, such as the large Atherosclerosis Risk in Communities (ARIC) study. Additionally, various cross-sectional and follow-up studies in patients with ARDs have demonstrated associations between ocular vessel changes, traditional CV risk scores, and disease-related characteristics, suggesting a potential role for ocular assessments in CV risk screening. In this review work, research from 26 studies retrieved from the PubMed and Web of Science databases has been highlighted. Herein, we evaluate the techniques of retinal vessel analysis (RVA), optical coherence tomography angiography (OCT-A), spectral domain-OCT (SD-OCT), and retrobulbar color Doppler. Specifically, we examine the available data on their associations with key CV risk factors, systemic inflammation, surrogate CV markers, and traditional CV risk scores. Furthermore, we discuss their potential diagnostic value in both ARDs and the general population. Despite current limitations, such as small sample sizes and methodological heterogeneity, initial findings suggest that these techniques may provide valuable insights into microangiopathy and CV risk. Future research should focus on larger, well-designed longitudinal studies to establish their prognostic value and potential integration into clinical practice.},
	doi = {10.3389/fimmu.2025.1543157},
	pmid = {40303406 [Indexed for MEDLINE]},
	note = {PMC12037583}
}

@ARTICLE{10.1111/ceo.14538,
	author = {Gin TJ and Surendran SA and Rogers SL and Lim LL},
	title = {Predictive Factors for Uveitis Refractory to Treatment in Initial-Onset Acute Vogt-Koyanagi-Harada Disease.},
	journal = {Clin Exp Ophthalmol},
	year = {2025},
	abstract = {BACKGROUND: To identify predictive factors of uveitis refractory to treatment in initial-onset acute Vogt-Koyanagi-Harada disease. METHODS: This was a retrospective chart review of patients with initial-onset acute Vogt-Koyanagi-Harada disease presenting to the Royal Victorian Eye and Ear Hospital, Melbourne, Australia between July 2001 and March 2023 inclusive. Factors predictive of uveitis refractory to treatment were determined using logistic regression models with, and without, adjustment for initial use of intravenous methylprednisolone. RESULTS: Thirty-eight patients with initial-onset acute Vogt-Koyanagi-Harada were included, 27 of whom received initial intravenous corticosteroids (71%) and 23 met the criteria for uveitis refractory to treatment (61%). Comparing those who received intravenous corticosteroids to those who did not, the incidence of complications, time-to-quiescence, time-to-relapse, time-to-low dose corticosteroid or corticosteroid-sparing control of inflammation and time-to-remission were not statistically different (all p > 0.164). Factors at onset of treatment that were predictive for uveitis refractory to treatment included greater anterior chamber inflammation (p = 0.008), greater vitreous inflammation (p = 0.015), the absence of bacillary layer detachments on macular optical coherence tomography (p = 0.010) and commencement of systemic steroid therapy 1 week or longer after ocular symptom onset (p = 0.013). Absence of intravenous corticosteroids as initial therapy was not a statistically significant predictive factor for refractory disease (p = 0.802). CONCLUSIONS: Delayed commencement of systemic steroid therapy and higher severity of intraocular inflammation at presentation are predictive of initial-onset acute Vogt-Koyanagi-Harada disease evolving into disease refractory to treatment.},
	doi = {10.1111/ceo.14538},
	pmid = {40254294 [Indexed for MEDLINE]}
}

@ARTICLE{10.1038/s41598-025-96579-2,
	author = {Kato K and Shinoda K and Yokogawa N and Tajima T and Takahashi T and Kondo M},
	title = {A real-world descriptive study of screening practices for hydroxychloroquine retinopathy in Japan using an insurance claims database.},
	journal = {Sci Rep},
	year = {2025},
	abstract = {Since 2015, hydroxychloroquine (HCQ) has been widely used as a standard treatment for systemic lupus erythematosus (SLE) and cutaneous lupus erythematosus (CLE) under the national health insurance system in Japan. However, the status of routine ophthalmological screening for retinopathy, which is a notable safety concern of HCQ, remains unclear. In this retrospective study using the nationwide health insurance claims database, we aimed to investigate the status of ophthalmological screening in routine clinical practice in Japan. A total of 2567 patients with SLE or CLE were included in the analysis. The proportion of ophthalmology visits was 88.0% at the initiation of HCQ prescription, decreased to 76.3% after one year, and then remained constant. Moreover, only 50% of the patients underwent spectral-domain optical coherence tomography (SD-OCT) and automated visual field (VF) tests, which are useful for the early detection of HCQ retinopathy-related changes. Importantly, the proportion of ophthalmology visits remained consistently high among patients who visited an ophthalmologist in the previous year, ranging from 77.3% to 90.2%. These findings highlight the need to improve screening adherence and promote regular ophthalmological evaluations, particularly for patients without prior ophthalmology visits, to enhance the early detection of HCQ retinopathy.},
	doi = {10.1038/s41598-025-96579-2},
	pmid = {40210937 [Indexed for MEDLINE]},
	note = {PMC11985982}
}

@ARTICLE{10.1016/j.phymed.2025.156660,
	author = {Liao W and Hu R and Ji Y and Zhong Z and Huang X and Cai T and Zhou C and Wang Y and Ye Z and Yang P},
	title = {Oleic acid regulates CD4+ T cells differentiation by targeting ODC1-mediated STAT5A phosphorylation in Vogt-Koyanagi-Harada disease.},
	journal = {Phytomedicine},
	year = {2025},
	abstract = {BACKGROUND: Vogt-Koyanagi-Harada (VKH) is a multisystemic autoimmune disorder characterized by bilateral panuveitis frequently accompanied by neurologic manifestations. While metabolic dysregulation is increasingly recognized in the context of autoimmune diseases, the role of specific metabolites in VKH disease remains unexplored. METHODS: Non-targeted and targeted metabolomics analysis, phospho-antibody array, proteome microarray, surface plasmon resonance, and molecular simulation were used to identify molecular target of OA. RESULTS: We investigated metabolic profile of VKH disease and found that oleic acid (OA) was enriched in this disease. A series of functional assays showed that OA could exacerbate experimental autoimmune uveitis (EAU) in association with increased frequency of Th1 and Th17 cells and decreased proportion of Treg cells in vitro. However, the specific molecular target of OA remains elusive. Through proteome microarrays, molecular simulations and surface plasmon resonance assays, Ornithine decarboxylase 1 (ODC1) was identified as target protein of OA. OA could bind to ODC1, increase ODC1 protein expression in both a time- and concentration-dependent manner and promote subsequently putrescine production. Phospho-antibody array analysis revealed that OA inhibited phosphorylation of STAT5A (Y694) in CD4+T cells, leading to imbalance of Th1/Th17 and Treg cells and decreased transcription of IL-10. OA upregulated ODC1 protein and putrescine levels through binding to LYS-78, inhibited phosphorylation of STAT5A protein and subsequently decreased binding of STAT5A at IL-10 promoter. CONCLUSION: These results reveals that OA could be a crucial metabolite for modulation of CD4+T cell differentiation and that ODC1-mediated phosphorylation and transcriptional activity of STAT5A contributes to development of VKH disease progression, highlighting ODC1 as a novel therapeutic target in VKH disease.},
	doi = {10.1016/j.phymed.2025.156660},
	pmid = {40203473 [Indexed for MEDLINE]}
}

@ARTICLE{10.1136/jitc-2024-011049,
	author = {Chang EL and Liu R and Keyhanian K and Huynh K and Berkenstock M and Bhatti MT and Chen JJ and Chodosh J and Costello F and Dalvin LA and DeLott LB and Dinkin M and Egan RA and Fraser CL and Freitag SK and Gangaputra S and Gordon LK and Guidon AC and Johnson DB and Kombo N and Kramer M and Lee AG and Levy M and Lobo-Chan AM and Mantopoulos D and Papaliodis G and Pless M and Pimkina J and Rubin KM and Sen HN and Shariff A and Subramanian PS and Tsui E and Yoon MK and McDunn J and Rine J and Reynolds KL and Sobrin L and Chwalisz BK},
	title = {Consensus disease definitions for ophthalmic immune-related adverse events of immune checkpoint inhibitors.},
	journal = {J Immunother Cancer},
	year = {2025},
	abstract = {Ophthalmic immune-related adverse events (Eye-irAEs) from immune checkpoint inhibitors can cause visual morbidity. The absence of standardized definitions for Eye-irAEs not only impedes the development of evidence-based treatments but also progress in translational research. The objective of this study was to develop consensus guidance for an approach to Eye-irAEs.Four ophthalmic physicians (uveitis specialists and neuro-ophthalmologists) drafted Eye-irAE consensus guidance and definitions, which were reviewed by the multidisciplinary Eye-irAE definition panel. The panel was divided into Group A (Neuro-ophthalmology/Orbital Disease) and Group B (Uveitis/Ocular Surface Disease). A modified Delphi consensus process was used, with two rounds of anonymous ratings by panelists and two meetings to discuss areas of controversy. For each disorder, five diagnostic components were evaluated: symptoms, examination findings, laboratory studies/imaging findings, diagnostic criteria, and treatment. Panelists rated content for usability, appropriateness and accuracy on 9-point scales in electronic surveys and provided free-text comments. Aggregated survey responses were incorporated into revised definitions. Consensus was based on numeric ratings using the RAND Corporation/ University of California Los Angeles Health Services Utilization Study (RAND/UCLA) Appropriateness Method with prespecified definitions.29 panelists from 25 academic medical centers voted on 114 rating scales (66 neuro-ophthalmic/orbital disease components, 48 uveitis/ocular surface disease components); of these, 86.3% (57/66) in Group A and 89.6% (43/48) in Group B reached first-round consensus. After revisions, all items except 6.1% (4/66) in Group A and 1.6% (1/60) in Group B received second-round consensus. Consensus definitions were achieved for 10/11 neuro-ophthalmic/orbital disorders: optic neuritis, inflammatory optic disc edema, arteritic ischemic optic neuropathy, optic perineuritis, orbital inflammation, thyroid eye disease-like orbital inflammation, cavernous sinus syndrome, oculomotor mononeuritis, trochlear mononeuritis, and abducens mononeuritis. Consensus definitions were achieved for 9/10 uveitis/ocular surface disorders: anterior uveitis, intermediate uveitis, posterior uveitis, panuveitis, Vogt-Koyanagi-Harada-like syndrome, sarcoidosis-like syndrome, acute macular neuroretinopathy, dry eye disease, and scleritis.These disease definitions establish a standardized classification for Eye-irAE, highlighting differences between irAEs and other inflammatory disorders. Importantly, diagnostic certainty does not always align directly with the need to treat as an Eye-irAE. Given the consensus from this representative panel group, it is anticipated the definitions will be used broadly across clinical and research settings.},
	doi = {10.1136/jitc-2024-011049},
	pmid = {40199607 [Indexed for MEDLINE]},
	note = {PMC11979595}
}

@ARTICLE{10.1172/jci.insight.184072,
	author = {Wang T and Duan R and Li Z and Zhang B and Jiang Q and Jiang L and Lv J and Su W and Feng L},
	title = {Lipid metabolism analysis reveals that DGAT1 regulates Th17 survival by controlling lipid peroxidation in uveitis.},
	journal = {JCI Insight},
	year = {2025},
	abstract = {Lipid metabolism is closely linked with antitumor immunity and autoimmune disorders. However, the precise role of lipid metabolism in uveitis pathogenesis is not clear. In our study, we analyzed the single-cell RNA-Seq (scRNA-Seq) data from cervical draining lymph nodes (CDLNs) of mice with experimental autoimmune uveitis (EAU), revealing an increased abundance of fatty acids in Th17 cells. Subsequent scRNA-Seq analysis identified the upregulation of DGAT1 expression in EAU and its marked reduction under various immunosuppressive agents. Suppression of DGAT1 prevented the conversion of fatty acids into neutral lipid droplets, resulting in the accumulation of lipid peroxidation and subsequent reduction in the proportion of Th17 cells. Inhibiting lipid peroxidation by Ferrostatin-1 effectively restored Th17 cell numbers that were decreased by DGAT1 inhibitor. Moreover, we validated the upregulation of DGAT1 in CD4+ T cells from patients with Vogt-Koyanagi-Harada (VKH) disease, a human uveitis. Inhibiting DGAT1 induced lipid peroxidation in human CD4+ T cells and reduced the proportion of Th17 cells. Collectively, our study focused on elucidating the regulatory mechanisms underlying Th17 cell survival and proposed that targeting DGAT1 may hold promise as a therapeutic approach for uveitis.},
	doi = {10.1172/jci.insight.184072},
	pmid = {40197365 [Indexed for MEDLINE]},
	note = {PMC11981632}
}

