@ARTICLE{10.1038/s41598-025-93223-x,
	author = {Yanai R and Uchi SH and Kondo Y and Fujitsu Y and Suzuki K and Yoshimura K and Kumagai N and Egawa M and Mitamura Y},
	title = {The epidemiology of uveitis: comparison of its causes and visual outcomes between three-tiered medical facilities in Ube city.},
	journal = {Sci Rep},
	year = {2025},
	abstract = {This study aimed to conduct a comparative epidemiological survey of uveitis across various healthcare settings and elucidate the clinical characteristics. We conducted a retrospective cross-sectional study in the Ube-City medical region in Yamaguchi prefecture and recruited 268 patients from a university hospital (151 patients), municipal hospitals (51 patients), and private eye clinics (58 patients). Medical records of patients newly diagnosed with uveitis between January 2018 and December 2019 in the institutes were included, reviewed, and compared. The main outcomes included the number of uveitis causes, treatment methods, and visual acuity. Panuveitis, which is associated with systemic diseases, such as Vogt-Koyanagi-Harada disease and sarcoidosis, was more prominent in university hospital patients. Conversely, anterior uveitis, including traumatic iritis, was prominently detected in general hospitals and private eye clinics. The best-corrected visual acuity improved to 1.0 (logMAR = 0); an improvement of 74%, 61%, and 54% was observed in private eye clinic, general hospital, and university hospital patients, respectively. This study identified differences in uveitis presentation and treatment across diverse clinical settings. The results of this study provide valuable data for differentiating the causes of uveitis at university hospitals, general hospitals, and private eye clinics.},
	doi = {10.1038/s41598-025-93223-x},
	pmid = {40089526 [Indexed for MEDLINE]},
	note = {PMC11910647}
}

@ARTICLE{10.3389/fimmu.2025.1514306,
	author = {Peng C and Jiao Y and Chen C},
	title = {Unilateral choroidal detachment in an elderly patient with Vogt-Koyanagi-Harada disease: a case report and literature review.},
	journal = {Front Immunol},
	year = {2025},
	abstract = {PURPOSE: To report an uncommon case of Vogt-Koyanagi-Harada (VKH) disease in an elderly patient with unilateral choroidal detachment and describe its multimodal imaging features and prognosis. METHOD: Case report and literature review of clinical features in VKH with choroidal detachment. RESULTS: A 76-year-old woman presented with bilateral blurred vision and headache 6 months prior to visiting our hospital. She was diagnosed with iridocyclitis at another hospital and received local anti-inflammatory treatment without improvement. Slit-lamp examination showed bilateral mutton-fat and dust-like keratic precipitates, anterior chamber and vitreous cells, and posterior synechiae in the right eye. Fundus examination revealed bilateral optic disc swelling and choroidal detachment in the left eye. Fluorescein angiography revealed bilateral optic disc leakage, punctate hyperfluorescence in the posterior pole, and elevated fluorescence leakage in the left eye's temporal area. Indocyanine Green Angiography showed multiple of choroidal hypoperfusion areas in the left eye, with an elevated fluorescence blockage on the temporal side. Optical coherence tomography showed subretinal fluid, wavy retinal pigment epithelium, and choroidal thickening in both eyes. Based on ocular and neurological findings, the patient was diagnosed with bilateral VKH. After ruling out infectious factors, she received high-dose systemic corticosteroids and immunosuppressants. The choroidal detachment and serous retinal detachment gradually resolved. CONCLUSION: This case is the first report of unilateral choroidal detachment associated with VKH in an elderly patient. VKH patients with choroidal detachment reported in previous studies were predominantly elderly and Asian, characterized by optic disc hyperfluorescence and choroidal detachment. Multimodal imaging can help clinicians better diagnose and manage atypical types of VKH.},
	doi = {10.3389/fimmu.2025.1514306},
	pmid = {40083559 [Indexed for MEDLINE]},
	note = {PMC11903423}
}

@ARTICLE{10.1038/s41433-025-03720-6,
	author = {Urzua CA and Olate-Perez A and Anguita R and Schlaen A and Munk MR, Carreño E and Garza-Leon M and Sainz-de-la-Maza M and Adan A and Takeuchi M and Pavesio C and Sabat PE and Labbe E and Duarte G and Couto C and Cuitino L and Arellanes-Garcia L and Fuseau M and Cairoli E and Vidal R and Curi A, de-la-Torre A and Concha-Del-Rio LE},
	title = {Vogt-Koyanagi-Harada-like disease secondary to anticancer treatment: a multicentre case series.},
	journal = {Eye (Lond)},
	year = {2025},
	abstract = {OBJECTIVE: To describe the clinical features of a case series of patients with Vogt-Koyanagi-Harada (VKH)-like disease secondary to anticancer treatment. METHODS: Retrospective, non-interventional multicentre case-series study. Seventeen patients (34 eyes) with VKH-like disease secondary to anticancer treatment, seen between 2014 and 2023. Main outcome measures were patients' extraocular and ophthalmic clinical features, treatment, visual outcome, and complications. RESULTS: Fourteen out of 17 patients presented with skin melanoma. The main anticancer therapies were BRAF/MEK inhibitor (8/17 patients) and PD1 inhibitor (4/17 patients). Fifteen patients presented with ocular symptoms within 16 weeks after initiating anticancer therapy. Most of the eyes exhibited anterior chamber cells (n = 30), flare (n = 20), and vitritis (n = 11). All patients had subretinal fluid, and 24/34 eyes had foveal involvement. The mean subfoveal choroidal thickness measured by EDI-OCT was 483.42 ± 262.46 μm. In 12 cases, the oncology team decided to stop the anticancer therapy, and all but one patient was treated with high-dose oral corticosteroids for a median of 16 weeks. At the last follow-up visit, control of ocular inflammation had been achieved in 16 cases (median follow-up: 62 weeks, range 16-104 weeks). The most common complications were cataract and ocular hypertension (10 patients). CONCLUSIONS: VKH-like features in the context of emerging novel anticancer therapies represent a unique clinical phenotype in which the cornerstone of management should include high doses of systemic corticosteroids, using immunomodulatory therapy as a second-line treatment in patients with a refractory disorder. In addition, a comprehensive multidisciplinary approach, including an oncologist, should consider the safety of anticancer treatment cessation.},
	doi = {10.1038/s41433-025-03720-6},
	pmid = {40082704 [Indexed for MEDLINE]},
	note = {PMC12130264}
}

@ARTICLE{10.1007/s10633-025-10011-8,
	author = {Kato K and Nagashima R and Matsubara H and Yonekawa Y and Kashima Y and Mizumoto K and Kondo M},
	title = {Case of uveitis with increased electroretinographic amplitudes following Nivolumab and Ipilimumab administration for malignant melanoma.},
	journal = {Doc Ophthalmol},
	year = {2025},
	abstract = {PURPOSE: To report our flicker electroretinographic (ERG) findings in a patient who developed uveitis after treatment with immune checkpoint inhibitors (ICIs) for a metastatic malignant melanoma. METHODS: ERGs were used to monitor retinal physiology in a patient with ocular complications following systemic ICI administration. Flicker ERGs were recorded using the RETeval system before and after the ICI treatments. RESULTS: A 45-year-old woman was referred to our ophthalmologic clinic for baseline evaluations prior to initiating nivolumab/ipilimumab therapy. The patient had no ocular or ERG abnormalities at the initial visit, but three weeks after starting nivolumab/ipilimumab, she developed conjunctival hyperemia and tearing. Slit-lamp examination showed anterior chamber inflammation, and the ERGs showed a 40% increase in the amplitude from the baseline. However, optical coherence tomography (OCT) did not show any abnormalities. The anterior segment inflammation and increased ERG amplitude resolved with topical betamethasone. The patient developed significant liver damage after the second administration of nivolumab/ipilimumab, and this therapy was discontinued. Two steroid pulse therapies were followed by tapered oral prednisolone. During the follow-up period, no significant abnormalities were observed in the visual acuity or OCT images, but the ERG amplitudes increased from the first to the eighth month after the liver damage was detected. Five years later, the ERGs and OCT findings were within the normal limits, but she had developed a sunset glow fundus in both eyes. CONCLUSION: ERGs may be a useful objective test for posterior inflammation induced by administration of ICIs that is not evident in OCT images.},
	doi = {10.1007/s10633-025-10011-8},
	pmid = {40072695 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fphar.2025.1484320,
	author = {Maitiyaer M and Li P and Li H and Jiang D and Zhang J and Yang C and Yang X and Chen C and Huang W and Liu Z and Yu S},
	title = {The neutrophil-to-C3 ratio: unveiling diagnostic efficacy for lupus nephritis and association with reduced retinal vascular density in systemic lupus erythematosus.},
	journal = {Front Pharmacol},
	year = {2025},
	abstract = {BACKGROUND: Lupus nephritis (LN) frequently manifests as a significant complication in systemic lupus erythematosus (SLE) patients, with emerging research indicating a plausible correlation between subclinical retinal involvement and renal manifestations. This study aims to investigate the relationship between the neutrophil-to-C3 ratio (NC3R) and both LN as well as retinal microvasculature damage among SLE patients. METHODS: In this cross-sectional study, a cohort of 220 participants (78 LN and 142 non-LN) was recruited. We assessed clinical indicators and organ involvement and conducted correlation analyses between NC3R and markers of lupus activity. Additionally, we analyzed the diagnostic performance of NC3R in diagnosing LN and constructed ROC curves. Variables such as clinical and laboratory data were screened by univariate and least absolute shrinkage and selection operator (LASSO) logistic regression modeling. After 10-fold cross-validation, the predictive model was built by multivariate logistic regression. We further examined the influence of NC3R on retinal vasculature density based on its cutoff value and conducted correlation analyses accordingly. RESULTS: The LN group exhibited a significant increase in NC3R compared to the group without LN (5.9 vs. 4.5, p = 0.007). NC3R demonstrated positive correlations with 24-h proteinuria (R = 0.329, p < 0.001) and systemic lupus erythematosus disease activity index (SLEDAI) score (R = 0.268, p < 0.001). Multiple regression analysis revealed NC3R as an independent risk factor for LN (OR: 2.03, p = 0.025). NC3R was proven valuable in distinguishing LN patients (AUC: 0.613), with an optimal cutoff value of 6.40 (sensitivity: 48.1%, specificity: 72.0%). Our results indicated that the lower NC3R group (NC3R < 6.40) exhibited reduced vascular density, particularly within the macular region. Furthermore, we observed a positive correlation between NC3R levels and vascular density. CONCLUSION: NC3R demonstrated promising potential as a reliable indicator for predicting both LN and retinal microvasculature involvement. Consequently, the pre-treatment evaluation of NC3R had the potential to assist clinicians in identifying potential organ involvement among SLE patients.},
	doi = {10.3389/fphar.2025.1484320},
	pmid = {40046753},
	note = {PMC11880234}
}

@ARTICLE{10.1167/iovs.66.2.68,
	author = {Zhou H and Hu Y and Qin G and Kong J and Hong X and Guo C and Zou J and Feng L},
	title = {The Signature of Serum Modified Nucleosides in Uveitis.},
	journal = {Invest Ophthalmol Vis Sci},
	year = {2025},
	abstract = {PURPOSE: This study aims to evaluate the metabolism of serum-modified nucleosides in uveitis by using liquid chromatography-tandem mass spectrometry (LC-MS) and to develop potential diagnostic biomarkers for uveitis. METHODS: Forty-two patients with different subtypes of uveitis (idiopathic uveitis, Vogt-Koyanagi-Harada [VKH] disease, and ankylosing spondylitis [AS]) and 32 healthy controls were recruited in this retrospective case-control study. The concentrations of 23 modified nucleosides in patient serum were quantified by LC-MS. The data was statistically analyzed with SPSS and GraphPad Prism. RESULTS: The data revealed that 13 out of 23 modified nucleosides (m6A, m1A, m6Am, Cm, ac4C, Gm, m1G, m2G, m2,2G, Um, m3U, m5U, and m5Um) effectively showed quantifiable chromatographic peaks. The statistical results indicated that there were extremely significant differences for m2G, Gm, Cm, and m1G between healthy controls and uveitis patients. The differences for Gm, m6A,and m5U were able to further assort idiopathic uveitis and uveitis with systemic inflammation including VKH and AS. Interestingly, each specific subtype of uveitis is characterized by its signature combination of serum-modified nucleotides comparing with healthy controls. CONCLUSIONS: This study revealed that the metabolism of serum-modified nucleosides in uveitis patients display significant differences from healthy controls. The signature combination of serum modified nucleotides for each subtype of uveitis may be applied for the potential diagnosis of uveitis.},
	doi = {10.1167/iovs.66.2.68},
	pmid = {40014362 [Indexed for MEDLINE]},
	note = {PMC11875031}
}

